(function() {
var rev_ch_1_Verses = [
  {num:1,words:[["O le faaaliga a Iesu Keriso,", "The Revelation of Jesus Christ,"], ["na tuuina atu e le Atua ia te ia ina ia faaali mai i ana auauna o mea e tusa ona vave oo mai,", "which God gave unto him, to shew unto his servants things which must shortly come to pass;"], ["ua auina mai foi e ia lana agelu e faailoa mai ai i lana auauna o Ioane,", "and he sent and signified it by his angel unto his servant John:"]]},
  {num:2,words:[["o le na molimau i le afioga a le Atua,", "Who bare record of the word of God,"], ["ma le mau ia Iesu Keriso,", "and of the testimony of Jesus Christ,"], ["o mea uma foi na ia vaaia.", "and of all things that he saw."]]},
  {num:3,words:[["Amuia lē faitau,", "Blessed is he that readeth,"], ["atoa ma e faalogologo i upu o lenei valoaga,", "and they that hear the words of this prophecy,"], ["ma tausi i mea ua tusia ai;", "and keep those things which are written therein:"], ["auā ua latalata ona po.", "for the time is at hand."]]},
  {num:4,words:[["O a'u o Ioane o la'u tusi lenei i ekalesia e fitu o i Asia;", "John to the seven churches which are in Asia:"], ["ia ia te outou le alofa tunoa ma le manuia mai ia te ia o loo soifua,", "Grace be unto you, and peace,"], ["na soifua foi,", "from him which is,"], ["o le a afio mai;", "and which was, and which is to come;"], ["mai Agaga foi e toafitu o i luma o lona nofoālii;", "and from the seven Spirits which are before his throne;"]]},
  {num:5,words:[["mai ia Iesu Keriso foi,", "And from Jesus Christ,"], ["o le molimau faamaoni,", "who is the faithful witness,"], ["o le ulumatua o e ua oti,", "and the first begotten of the dead,"], ["ma le pule i tupu o le lalolagi. O le na alofa mai ia te i tatou,", "and the prince of the kings of the earth. Unto him that loved us,"], ["na ia fufulu mai foi ia te i tatou i a tatou agasala i lona lava toto,", "and washed us from our sins in his own blood,"]]},
  {num:6,words:[["na ia faia foi i tatou ma tupu ma faitaulaga i le Atua o lona lava Tamā,", "And hath made us kings and priests unto God and his Father;"], ["ia ia te ia le viiga ma le malosi e faavavau faavavau lava. Amene.", "to him be glory and dominion for ever and ever. Amen."]]},
  {num:7,words:[["Faauta,", "Behold,"], ["o loo afio mai o ia ma ao,", "he cometh with clouds;"], ["e iloa atu foi o ia e mata o tagata uma,", "and every eye shall see him,"], ["atoa ma e na tu'ia o ia;", "and they also which pierced him:"], ["e taufaitagitu'i foi itu aiga uma o le lalolagi ona o ia. E moni,", "and all kindreds of the earth shall wail because of him. Even so,"], ["Amene.", "Amen."]]},
  {num:8,words:[["O a'u le Alefa ma le Omeka,", "I am Alpha and Omega,"], ["o le amataga ma le gataaga,", "the beginning and the ending,"], ["ua fetalai mai ai le Alii,", "saith the Lord,"], ["o loo soifua,", "which is,"], ["na soifua foi,", "and which was,"], ["o le a afio mai,", "and which is to come,"], ["e ona le malosi uma lava.", "the Almighty."]]},
  {num:9,words:[["O a'u o Ioane,", "I John,"], ["o lo outou uso ma le ua faatasi ma outou i le puapuaga,", "who also am your brother, and companion in tribulation,"], ["ma le malo,", "and in the kingdom and patience of Jesus Christ,"], ["atoa ma le onosai o Iesu Keriso,", "was in the isle that is called Patmos, for the word of God,"], ["na a'u i le motu e igoa ia Patamo ona o le afioga a le Atua ma le mau ia Iesu Keriso.", "and for the testimony of Jesus Christ."]]},
  {num:10,words:[["Na ou i le Agaga i le aso o le Alii;", "I was in the Spirit on the Lord's day,"], ["ona ou faalogo ai lea i o'u tua i le leo tele e pei o se pu,", "and heard behind me a great voice,"], ["ua faapea mai,", "as of a trumpet,"]]},
  {num:11,words:[["O a'u le Alefa ma le Omeka,", "Saying,"], ["o le muamua ma le mulimuli;", "I am Alpha and Omega,"], ["i le ma lea,", "the first and the last: and,"], ["O mea e te vaaia ia e tusi i se tusi,", "What thou seest,"], ["ma avatu i ekalesia o i Asia,", "write in a book,"], ["o Efeso,", "and send it unto the seven churches which are in Asia;"], ["ma Semurana,", "unto Ephesus,"], ["ma Perekamo,", "and unto Smyrna,"], ["ma Tuatira,", "and unto Pergamos,"], ["ma Sarataisa,", "and unto Thyatira, and unto Sardis,"], ["ma Filatelefaia,", "and unto Philadelphia,"], ["ma Laotikaia.", "and unto Laodicea."]]},
  {num:12,words:[["Na ou fāliu atu e vaai i le leo na tautala mai ia te au; ua ou fāliu,", "And I turned to see the voice that spake with me. And being turned,"], ["ona ou iloa atu lea o tuugālamepa auro e fitu.", "I saw seven golden candlesticks;"]]},
  {num:13,words:[["Ua i totonu foi i tuugālamepa e fitu le tasi e pei o le Atalii o le tagata,", "And in the midst of the seven candlesticks one like unto the Son of man,"], ["ua ofu ia i le ofu tatapuvae,", "clothed with a garment down to the foot,"], ["ua fusia foi lona fatafata i le fusi auro;", "and girt about the paps with a golden girdle."]]},
  {num:14,words:[["ua sinasina foi lona ao ma ona lauao e pei o le fulufulu mamoe ona sinasina,", "His head and his hairs were white like wool,"], ["e pei o le kiona lava;", "as white as snow;"], ["o ona fofoga foi e pei o le mumū o le afi;", "and his eyes were as a flame of fire;"]]},
  {num:15,words:[["ma ona vae e pei o le 'apa pupula,", "And his feet like unto fine brass,"], ["e peiseai ua mu i le ogāumu;", "as if they burned in a furnace;"], ["o lona siufofoga foi e pei o le taalili o vai e tele;", "and his voice as the sound of many waters."]]},
  {num:16,words:[["ua i lona aao taumatau o fetu e fitu;", "And he had in his right hand seven stars:"], ["ua alu atu foi ai lona fofoga o le pelu e faataumaai ona itu e maamaai lava;", "and out of his mouth went a sharp twoedged sword:"], ["o ona fofoga foi e pei o le pupula o le la ina o mu toto'a.", "and his countenance was as the sun shineth in his strength."]]},
  {num:17,words:[["Ua ou iloa atu ia te ia,", "And when I saw him,"], ["ona ou paū ifo lea i ona vae e peiseai ua oti;", "I fell at his feet as dead. And he laid his right hand upon me,"], ["a ua ia faaee mai lona aao taumatau i luga ia te au, ua faapea mai ia te au,", "saying unto me,"], ["Aua e te fefe;", "Fear not;"], ["o a'u le muamua ma le mulimuli;", "I am the first and the last:"]]},
  {num:18,words:[["o lē ola nei lava,", "I am he that liveth,"], ["sa ou oti,", "and was dead;"], ["faauta foi,", "and, behold,"], ["ou te ola e faavavau faavavau lava;", "I am alive for evermore,"], ["Amene,", "Amen;"], ["o ia te au foi ki o seoli ma le oti.", "and have the keys of hell and of death."]]},
  {num:19,words:[["Ia e tusi i mea na e iloa,", "Write the things which thou hast seen,"], ["ma mea o i ai nei,", "and the things which are,"], ["atoa ma mea e tutupu amuli;", "and the things which shall be hereafter;"]]},
  {num:20,words:[["o le uiga lilo o fetu e fitu na e iloa i lo'u lima taumatau,", "The mystery of the seven stars which thou sawest in my right hand,"], ["ma tuugālamepa auro e fitu.", "and the seven golden candlesticks."], ["O fetu e fitu o agelu ia a ekalesia e fitu; o tuugālamepa foi e fitu na e iloa,", "The seven stars are the angels of the seven churches:"], ["o ekalesia ia e fitu.", "and the seven candlesticks which thou sawest are the seven churches."]]},
];
renderVerseSet(rev_ch_1_Verses, 'rev-ch1-verses');

var rev_ch_2_Verses = [
  {num:1,words:[["Ia e tusi i le agelu a le ekalesia o i Efeso. O mea nei ua fai mai ai lē 'u'u i fetu e fitu i lona lima taumatau,", "Unto the angel of the church of Ephesus write; These things saith he that holdeth the seven stars in his right hand,"], ["o lē savali i totonu o tuugālemepa auro e fitu.", "who walketh in the midst of the seven golden candlesticks;"]]},
  {num:2,words:[["Ua ou iloa i au galueaga,", "I know thy works,"], ["ma lou tiga,", "and thy labour,"], ["ma lou onosai,", "and thy patience,"], ["ina ua e le lavatia i e ua leaga;", "and how thou canst not bear them which are evil:"], ["ua e tofotofo foi i e ua fai mai o aposetolo i latou,", "and thou hast tried them which say they are apostles,"], ["a e leai lava,", "and are not,"], ["ua e iloa foi o tagata pepelo i latou,", "and hast found them liars:"]]},
  {num:3,words:[["ma ua e lavatia,", "And hast borne,"], ["ua ia te oe foi le onosai,", "and hast patience,"], ["ua e tautiga ona o lo'u igoa,", "and for my name's sake hast laboured,"], ["e te lei faavaivai lava.", "and hast not fainted."]]},
  {num:4,words:[["A ua ou iloa se mea ia te oe,", "Nevertheless I have somewhat against thee,"], ["ona ua e tuua o lou uluai alofa.", "because thou hast left thy first love."]]},
  {num:5,words:[["O lenei,", "Remember therefore from whence thou art fallen,"], ["ia e manatua le mea na e paū mai ai,", "and repent,"], ["ma ia e salamo, ma e faia au uluai galuega;", "and do the first works;"], ["afai e leai,", "or else I will come unto thee quickly,"], ["ona ou vave alu atu lea ia te oe,", "and will remove thy candlestick out of his place,"], ["ou te aveesea lau tuugālamepa i le mea e tuu ai pe afai e te le salamo.", "except thou repent."]]},
  {num:6,words:[["A ua ia te oe lenei mea,", "But this thou hast,"], ["ina ua e 'ino'ino i galuega a le au Nikalaitai,", "that thou hatest the deeds of the Nicolaitans,"], ["o a'u foi ou te 'ino'ino i ai.", "which I also hate."]]},
  {num:7,words:[["O le ua i ai taliga,", "He that hath an ear,"], ["ina faalogo mai ia o ia i le mea ua fetalai mai ai le Agaga i ekalesia,", "let him hear what the Spirit saith unto the churches;"], ["O lē manumalo,", "To him that overcometh will I give to eat of the tree of life,"], ["ou te avatua ia te ia e 'ai i le laau o le ola o i totonu o le parataiso o le Atua.", "which is in the midst of the paradise of God."]]},
  {num:8,words:[["Ia e tusi foi i le agelu a le ekalesia o i Semurana,", "And unto the angel of the church in Smyrna write;"], ["O mea nei ua fai mai ai lē muamua ma lē mulimuli,", "These things saith the first and the last,"], ["o le na oti,", "which was dead,"], ["a ua ola mai,", "and is alive;"]]},
  {num:9,words:[["Ua ou iloa au galuega,", "I know thy works,"], ["ma lou puapuaga,", "and tribulation,"], ["ma lou mativa, (a ua e tamaoaiga,", "and poverty,"], [") ma le upu faifai a ē ua fai mai o Iutaia i latou,", "(but thou art rich) and I know the blasphemy of them which say they are Jews,"], ["a e leai lava,", "and are not,"], ["a o le sunako o Satani i latou.", "but are the synagogue of Satan."]]},
  {num:10,words:[["Aua lava e te fefe i mea o le a e tiga ai. Faauta,", "Fear none of those things which thou shalt suffer:"], ["o le a tuuina atu ni o outou e le tiapolo i le fale puipui,", "behold, the devil shall cast some of you into prison,"], ["ina ia tofotofoina ai outou;", "that ye may be tried;"], ["e po agafulu foi e puapuagatia ai outou. Ia e faamaoni seia oo i le oti,", "and ye shall have tribulation ten days: be thou faithful unto death,"], ["ona ou avatu ai lea ia te oe o le pale o le ola.", "and I will give thee a crown of life."]]},
  {num:11,words:[["O le ua i ai taliga,", "He that hath an ear,"], ["ina faalogo mai ia o ia i le mea ua fetalai mai ai le Agaga i ekalesia, O lē manumalo,", "let him hear what the Spirit saith unto the churches;"], ["e le afaina lava o ia i le oti faalua.", "He that overcometh shall not be hurt of the second death."]]},
  {num:12,words:[["Ia e tusi foi i le agelu a le ekalesia o i Perekamo,", "And to the angel of the church in Pergamos write;"], ["O mea nei ua fai mai ai le ua i ai le pelu e faatau maai ona itu ua maamaai lava,", "These things saith he which hath the sharp sword with two edges;"]]},
  {num:13,words:[["Ua ou iloa au galuega,", "I know thy works,"], ["ma le mea ua e nofo ai,", "and where thou dwellest, even where Satan's seat is:"], ["o i ai le nofoālii o Satani,", "and thou holdest fast my name,"], ["ua e taofi mau foi i lo'u igoa,", "and hast not denied my faith,"], ["ma ua e le faafitia le faatuatua ia te au i ia ona po lava na i ai Anetipa o la'u molimau o le na faamaoni,", "even in those days wherein Antipas was my faithful martyr, who was slain among you,"], ["sa fasiotia o ia na ia te outou i le mea o nofo ai Satani.", "where Satan dwelleth."]]},
  {num:14,words:[["A ua ia te au ni nai mea ia te oe,", "But I have a few things against thee,"], ["ona ua ia te oe o e ua taofi i le mataupu a Palaamo,", "because thou hast there them that hold the doctrine of Balaam,"], ["o le na a'oa'o ia Palako e tuu atu le mea e tausuai ai i luma o le fanauga a Isaraelu,", "who taught Balac to cast a stumblingblock before the children of Israel, to eat things sacrificed unto idols,"], ["ona ia aai i mea ua fāsia mo tupua ma ia latou faitaaga.", "and to commit fornication."]]},
  {num:15,words:[["E faapea foi ona ia te oe o e ua taofi i le mataupu a le au Nikalaitai;", "So hast thou also them that hold the doctrine of the Nicolaitans,"], ["o le mea ou te 'ino'ino i ai.", "which thing I hate."]]},
  {num:16,words:[["Ina e salamo ia;", "Repent;"], ["afai e leai, ona ou vave alu atu lea ia te oe,", "or else I will come unto thee quickly,"], ["ou te tau foi ma i latou i le pelu ai lo'u gutu.", "and will fight against them with the sword of my mouth."]]},
  {num:17,words:[["O le ua i ai taliga,", "He that hath an ear,"], ["ina faalogo mai ia o ia i le mea ua fetalai mai ai le Agaga i ekalesia,", "let him hear what the Spirit saith unto the churches;"], ["O lē manumalo, ou te avatua ia te ia le manai lilo e 'ai ai;", "To him that overcometh will I give to eat of the hidden manna,"], ["ou te avatu foi ia te ia le maa sinasina,", "and will give him a white stone,"], ["ua tusia foi i le maa le igoa fou,", "and in the stone a new name written,"], ["e le iloa e se tasi ua na o le ua maua.", "which no man knoweth saving he that receiveth it."]]},
  {num:18,words:[["Ia e tusi foi i le agelu a le ekalesia o i Tuatira,", "And unto the angel of the church in Thyatira write;"], ["O mea nei ua fai mai ai le Atalii o le Atua,", "These things saith the Son of God,"], ["o le e pei o le mumū o le afi ona mata,", "who hath his eyes like unto a flame of fire,"], ["o ona vae foi e pei o le 'apa pupula,", "and his feet are like fine brass;"]]},
  {num:19,words:[["Ua ou iloa au galuega ma lou alofa,", "I know thy works,"], ["ma lou auauna mai,", "and charity,"], ["ma lou faatuatua,", "and service, and faith,"], ["ma lou onosai,", "and thy patience,"], ["ma au galueaga,", "and thy works;"], ["ua sili mea mulimuli i mea na muamua.", "and the last to be more than the first."]]},
  {num:20,words:[["A ua ia te au ni nai mea ia te oe,", "Notwithstanding I have a few things against thee,"], ["ona ua e tuu pea le fafine o Iesepela,", "because thou sufferest that woman Jezebel,"], ["ua ta'ua o ia e ia o le perofeta fafine, e a'oa'o ma faasese i a'u auauna,", "which calleth herself a prophetess,"], ["ina ia faitaaga,", "to teach and to seduce my servants to commit fornication,"], ["ma aai mea ua fāsia mo tupua.", "and to eat things sacrificed unto idols."]]},
  {num:21,words:[["Ua ou tuu atu foi ni ona aso ia salamo ai i lana faitaaga,", "And I gave her space to repent of her fornication;"], ["a ua le salamo lava o ia.", "and she repented not."]]},
  {num:22,words:[["Faauta,", "Behold,"], ["o a'u ou te lafo ia te ia i le moega,", "I will cast her into a bed,"], ["atoa ma e ua mulilulua ma ia, ina ia puapuagateleina,", "and them that commit adultery with her into great tribulation,"], ["pe afai latou te le salamo i a latou galuega;", "except they repent of their deeds."]]},
  {num:23,words:[["ou te fāsia foi ana fanau ia oti;", "And I will kill her children with death;"], ["e iloa foi e ekalesia uma, o a'u lava o lē suesue i manao ma loto;", "and all the churches shall know that I am he which searcheth the reins and hearts:"], ["ou te avatua foi ia te outou taitoatasi e tusa ma a outou galuega.", "and I will give unto every one of you according to your works."]]},
  {num:24,words:[["A ou te fai atu ia te outou,", "But unto you I say,"], ["atoa ma nisi o i Tuatira,", "and unto the rest in Thyatira,"], ["o e ua le i ai lenei mataupu,", "as many as have not this doctrine,"], ["ma ua latou le iloa mea loloto a Satani,", "and which have not known the depths of Satan,"], ["(pei ona ta'ua e i latou,", "as they speak;"], [") Ou te le tuuina atu se isi avega ia te outou;", "I will put upon you none other burden."]]},
  {num:25,words:[["a e peitai o le mea ua ia te outou ia outou taofi mau ai, seia ou alu atu.", "But that which ye have already hold fast till I come."]]},
  {num:26,words:[["O lē manumalo foi,", "And he that overcometh,"], ["ma tausi i a'u galuega seia oo i le gataaga,", "and keepeth my works unto the end,"], ["ou te avatua ia te ia e pule i nuu ese;", "to him will I give power over the nations:"]]},
  {num:27,words:[["e pule foi o ia ia te i latou i le tootoo uamea;", "And he shall rule them with a rod of iron;"], ["e nutipalaina i latou pei o ipu a lē fai ipu omea,", "as the vessels of a potter shall they be broken to shivers:"], ["e pei o a'u foi ona ou maua mai i lo'u Tamā;", "even as I received of my Father."]]},
  {num:28,words:[["ou te avatua foi ia te ia le fetu ao.", "And I will give him the morning star."]]},
  {num:29,words:[["O le ua i ai taliga,", "He that hath an ear,"], ["ina faalogo mai ia o ia i le mea ua fetalai mai ai le Agaga i ekalesia.", "let him hear what the Spirit saith unto the churches."]]},
];
renderVerseSet(rev_ch_2_Verses, 'rev-ch2-verses');

var rev_ch_3_Verses = [
  {num:1,words:[["Ia e tusi foi i le agelu a le ekalesia,", "And unto the angel of the church in Sardis write;"], ["o i Sarataisa,", "These things saith he that hath the seven Spirits of God,"], ["O mea nei ua fai mai ai le ua i ai Agaga e toafitu o le Atua, ma fetu e fitu,", "and the seven stars;"], ["Ua ou iloa au galuega,", "I know thy works,"], ["ua ia te oe le igoa ua e ola,", "that thou hast a name that thou livest,"], ["a ua e oti.", "and art dead."]]},
  {num:2,words:[["Ia e mataala,", "Be watchful,"], ["ma ia e faatumauina mea ua totoe o le a mate;", "and strengthen the things which remain, that are ready to die:"], ["auā ou te lei iloa au galuega ona atoatoa i luma o le Atua.", "for I have not found thy works perfect before God."]]},
  {num:3,words:[["O lea foi ia e manatu ai i mea ua e maua ma ua e faalogo ai,", "Remember therefore how thou hast received and heard,"], ["ma ia e taofiina ai,", "and hold fast,"], ["ma ia e salamo. Afai foi e te le mataala,", "and repent. If therefore thou shalt not watch,"], ["ou te alu atu ia te oe e pei o se gaoi,", "I will come on thee as a thief,"], ["e te le iloa foi le itu aso ou te alu atu ai ia te oe.", "and thou shalt not know what hour I will come upon thee."]]},
  {num:4,words:[["Ua ia te oe ni nai tagata i Sarataisa lava,", "Thou hast a few names even in Sardis which have not defiled their garments;"], ["o e ua le faaeleelea o latou ofu; latou te savavali ma a'u i ofu sisina,", "and they shall walk with me in white:"], ["auā ua tatau ai i latou.", "for they are worthy."]]},
  {num:5,words:[["O lē manumalo,", "He that overcometh,"], ["e faaofuina o ia i ofu sisina;", "the same shall be clothed in white raiment;"], ["ou te le sōloiesea foi lona igoa i le tusi o le ola,", "and I will not blot out his name out of the book of life,"], ["a e ou te ta'u atu lona igoa i luma o lo'u Tamā,", "but I will confess his name before my Father,"], ["ma luma o ana agelu.", "and before his angels."]]},
  {num:6,words:[["O le ua i ai taliga,", "He that hath an ear,"], ["ina faalogo mai ia o ia i le mea ua fetalai mai ai le Agaga i ekalesia.", "let him hear what the Spirit saith unto the churches."]]},
  {num:7,words:[["Ia e tusi foi i le agelu a le ekalesia o i Filatelefaia,", "And to the angel of the church in Philadelphia write;"], ["O mea nei ua fai mai ai le Paia,", "These things saith he that is holy,"], ["o le faamaoni ia,", "he that is true,"], ["o le ua i ai le ki a Tavita,", "he that hath the key of David,"], ["o le na te talā,", "he that openeth,"], ["a e leai se na te faamauina;", "and no man shutteth;"], ["o le na te faamauina foi,", "and shutteth,"], ["a e leai se na te tatalaina;", "and no man openeth;"]]},
  {num:8,words:[["ua ou iloa au galuega;", "I know thy works:"], ["faauta,", "behold,"], ["ua ou tuuina atu i ou luma le faitotoa ua avanoa,", "I have set before thee an open door,"], ["e leai foi se na te mafaia ona punitia;", "and no man can shut it:"], ["auā ua ia te oe sina malosi itiiti,", "for thou hast a little strength,"], ["ma ua e tausia la'u upu,", "and hast kept my word,"], ["ma ua e le faafitia lo'u igoa.", "and hast not denied my name."]]},
  {num:9,words:[["Faauta,", "Behold,"], ["ou te tuuina atu i latou o i le sunako o Satani,", "I will make them of the synagogue of Satan,"], ["o e o fai mai o Iutaia i latou,", "which say they are Jews,"], ["a e leai lava,", "and are not,"], ["a ua pepelo i latou; faauta,", "but do lie;"], ["ou te ta'ita'i ia te i latou ina ia latou o atu i ou luma,", "behold,"], ["ma ifo atu i ou vae;", "I will make them to come and worship before thy feet,"], ["latou te iloa foi o a'u ua ou alofa atu ia te oe.", "and to know that I have loved thee."]]},
  {num:10,words:[["Ua e tausia le upu o lo'u onosai,", "Because thou hast kept the word of my patience,"], ["o lea foi ou te tausi ai ia te oe i le itu aso e tofotofoina ai,", "I also will keep thee from the hour of temptation,"], ["a oo mai i le lalolagi uma,", "which shall come upon all the world,"], ["e tofotofo ai i e o nonofo i le lalolagi.", "to try them that dwell upon the earth."]]},
  {num:11,words:[["Faauta,", "Behold,"], ["ou te vave alu atu;", "I come quickly:"], ["ia e taofi mau i le mea ua ia te oe,", "hold that fast which thou hast,"], ["ne'i avea e se tasi lou pale.", "that no man take thy crown."]]},
  {num:12,words:[["O lē manumalo,", "Him that overcometh will I make a pillar in the temple of my God,"], ["ou te faia lea ma pou tu i le malumalu o lo'u Atua,", "and he shall go no more out:"], ["e le toe ulufafo lava ia,", "and I will write upon him the name of my God,"], ["ou te tusi foi i ai le suafa o lo'u Atua,", "and the name of the city of my God,"], ["ma le igoa o le aai a lo'u Atua,", "which is new Jerusalem,"], ["o Ierusalema fou lea e alu ifo nai le lagi mai lo'u Atua,", "which cometh down out of heaven from my God:"], ["atoa foi ma lo'u igoa fou.", "and I will write upon him my new name."]]},
  {num:13,words:[["O le ua i ai taliga,", "He that hath an ear,"], ["ina faalogo mai ia o ia i le mea ua fetalai mai ai le Agaga i ekalesia.", "let him hear what the Spirit saith unto the churches."]]},
  {num:14,words:[["Ia e tusi foi i le agelu a le ekalesia o i Laotikaia,", "And unto the angel of the church of the Laodiceans write;"], ["O mea nei ua fai mai ai le Amene,", "These things saith the Amen,"], ["o le molimau moni ma le faamaoni,", "the faithful and true witness,"], ["o le amataga o mea na faia e le Atua,", "the beginning of the creation of God;"]]},
  {num:15,words:[["Ua ou iloa au galuega, e te le maalili,", "I know thy works,"], ["e te le vevela foi;", "that thou art neither cold nor hot:"], ["ou te loto ina ia e maalili, pe vevela;", "I would thou wert cold or hot."]]},
  {num:16,words:[["o lenei, ua e faaleogalua,", "So then because thou art lukewarm,"], ["e te le maalili,", "and neither cold nor hot,"], ["e te le vevela foi, o le mea lea ou te luai atu ai ia te oe i lo'u gutu", "I will spue thee out of my mouth."]]},
  {num:17,words:[["Auā ua e fai mai,", "Because thou sayest,"], ["Ou te se mauoa,", "I am rich,"], ["ua faatamaoaigaina a'u,", "and increased with goods,"], ["ou te le mativa foi i se mea e tasi;", "and have need of nothing;"], ["a ua e le iloa o oe o le malaia,", "and knowest not that thou art wretched,"], ["ma le pagatia,", "and miserable,"], ["ma le mativa,", "and poor,"], ["ma le tauaso,", "and blind,"], ["ma le le lavalava;", "and naked:"]]},
  {num:18,words:[["ou te fai atu ai ia te oe,", "I counsel thee to buy of me gold tried in the fire,"], ["ia e faatau atu ia te au le auro ua faamamāina i le afi,", "that thou mayest be rich;"], ["ina ia e tamaoaiga ai;", "and white raiment,"], ["ma ofu sisina ina ia e ofu ai,", "that thou mayest be clothed,"], ["ina ne'i iloa le mā o lou le lavalavā;", "and that the shame of thy nakedness do not appear;"], ["ma le vaimata e nini a'i ou mata,", "and anoint thine eyes with eyesalve,"], ["ina ia e pupula ai.", "that thou mayest see."]]},
  {num:19,words:[["Ou te aoai ma sasa ia i latou uma ou te alofa i ai;", "As many as I love,"], ["o lenei,", "I rebuke and chasten:"], ["ia e vilivilitai,", "be zealous therefore,"], ["ma ia e salamo.", "and repent."]]},
  {num:20,words:[["Faauta,", "Behold,"], ["ou te tu atu i le puipui ma tu'itu'i atu;", "I stand at the door,"], ["ai se tasi e faalogo mai i lo'u leo,", "and knock:"], ["ma tatala mai le puipui,", "if any man hear my voice, and open the door,"], ["ou te ulufale atu ia te ia,", "I will come in to him,"], ["ma te tali sua foi ma ia,", "and will sup with him,"], ["o ia foi ma a'u.", "and he with me."]]},
  {num:21,words:[["O lē manumalo ou te avatua i te ia ma te nonofo faatasi ma a'u i lo'u nofoālii,", "To him that overcometh will I grant to sit with me in my throne,"], ["e pei o a'u foi ona ou manumalo,", "even as I also overcame,"], ["ua ma nonofo foi faatasi ma lo'u Tamā i lona nofoālii.", "and am set down with my Father in his throne."]]},
  {num:22,words:[["O le ua i ai taliga,", "He that hath an ear,"], ["ina faalogo mai ia o ia i le mea ua fetalai mai ai le Agaga i ekalesia.", "let him hear what the Spirit saith unto the churches."]]},
];
renderVerseSet(rev_ch_3_Verses, 'rev-ch3-verses');

var rev_ch_4_Verses = [
  {num:1,words:[["Ua mavae atu ia mea,", "After this I looked,"], ["ona ou iloa atu lea,", "and,"], ["faauta,", "behold,"], ["o le faitotoa ua avanoa i le lagi,", "a door was opened in heaven:"], ["o le uluai leo foi na ou faalogo ai e pei o le pu ona tautala mai ia te au,", "and the first voice which I heard was as it were of a trumpet talking with me;"], ["ua faapea mai,", "which said,"], ["Ina sau ia i luga nei,", "Come up hither,"], ["ou te faaali atu ai ia te oe mea e tusa ona tutupu amuli.", "and I will shew thee things which must be hereafter."]]},
  {num:2,words:[["Ona a'u i le Agaga loa lea;", "And immediately I was in the spirit:"], ["faauta foi,", "and,"], ["ua tu mai le nofoālii i le lagi,", "behold, a throne was set in heaven,"], ["ua tietie foi le tasi i le nofoālii;", "and one sat on the throne."]]},
  {num:3,words:[["o lē tietie mai foi ua pei o le maa iasepi ma le salikea lona tino mai;", "And he that sat was to look upon like a jasper and a sardine stone: and there was a rainbow round about the throne,"], ["ua siosioina foi le nofoālii e le nuanua e pei o le samaraki lona tino mai.", "in sight like unto an emerald."]]},
  {num:4,words:[["Ua siosioina foi le nofoālii e nofoālii e luafulu ma le fa;", "And round about the throne were four and twenty seats:"], ["na ou iloa foi o toeaina e toaluafulu ma le toafa o tietie i ia nofoālii,", "and upon the seats I saw four and twenty elders sitting,"], ["ua oofu i ofu sisina;", "clothed in white raiment;"], ["ua i o latou ulu foi o pale auro.", "and they had on their heads crowns of gold."]]},
  {num:5,words:[["Ua oo mai foi uila, ma faititili,", "And out of the throne proceeded lightnings and thunderings and voices:"], ["ma leo mai le nofoālii;", "and there were seven lamps of fire burning before the throne,"], ["o lamepa foi e fitu o mumū i luma o le nofoālii, o Agaga ia e toafitu o le Atua.", "which are the seven Spirits of God."]]},
  {num:6,words:[["Ua i luma foi o le nofoālii le sami tioata,", "And before the throne there was a sea of glass like unto crystal:"], ["e pei o le maa tioata;", "and in the midst of the throne, and round about the throne,"], ["ua i totonu o le nofoālii ma ua liolioina le nofoālii e mea ola e fa ua tutumu i mata i luma atoa ma tua.", "were four beasts full of eyes before and behind."]]},
  {num:7,words:[["O le mea ola muamua e pei o le leona,", "And the first beast was like a lion,"], ["o lona lua o mea ola e pei o se povi taanoa,", "and the second beast like a calf,"], ["o lona tolu o mea ola e pei o le tagata ona mata,", "and the third beast had a face as a man,"], ["o lona fa foi o mea ola e pei o le aeto ua lele.", "and the fourth beast was like a flying eagle."]]},
  {num:8,words:[["O mea ola foi e fa e taitasi ma ona apaau e ono,", "And the four beasts had each of them six wings about him;"], ["ua faataaliolio ai,", "and they were full of eyes within:"], ["ma ua mata atoa i latou i totonu;", "and they rest not day and night,"], ["latou te le mapu lava i le ao ma le po i le fai atu,", "saying,"], ["E paia,", "Holy, holy,"], ["e paia,", "holy,"], ["e paia le Alii le Atua e ona le malosi uma lava,", "Lord God Almighty,"], ["o le na soifua,", "which was,"], ["o loo soifua foi,", "and is,"], ["o le a afio mai.", "and is to come."]]},
  {num:9,words:[["A vivii foi, ma faaneenee,", "And when those beasts give glory and honour and thanks to him that sat on the throne,"], ["ma faafetai atu mea ola i le o tietie i le nofoālli, o lē soifua e faavavau e faavavau lava,", "who liveth for ever and ever,"]]},
  {num:10,words:[["ona faapaū ai lea o toeaina e toaluafulu ma le toafa i luma o lē tietie i le nofoālii,", "The four and twenty elders fall down before him that sat on the throne,"], ["ma ifo atu i lē soifua e faavavau e faavavau lava,", "and worship him that liveth for ever and ever,"], ["ma lafo o latou pale i luma o le nofoālii,", "and cast their crowns before the throne,"], ["o loo faapea atu,", "saying,"]]},
  {num:11,words:[["Le Alii e,", "Thou art worthy,"], ["e tatau lava oe ina ia tuu atu ia te oe le viigia,", "O Lord,"], ["ma le faaneeneega, ma le mana;", "to receive glory and honour and power:"], ["auā na e faia mea uma lava,", "for thou hast created all things,"], ["ona o lou finagalo foi e i ai i latou ma ua faia.", "and for thy pleasure they are and were created."]]},
];
renderVerseSet(rev_ch_4_Verses, 'rev-ch4-verses');

var rev_ch_5_Verses = [
  {num:1,words:[["Na ou iloa foi i le aao taumatau o lē tietie i le nofoālii, o le tusi ua tusia i totonu ma le tua,", "And I saw in the right hand of him that sat on the throne a book written within and on the backside,"], ["ua faamauina i faamaufaailoga e fitu.", "sealed with seven seals."]]},
  {num:2,words:[["Na ou iloa foi le agelu malosi na tala'i atu ma le leo tele,", "And I saw a strong angel proclaiming with a loud voice,"], ["O ai ea e tatau ona fofola e ia o le tusi,", "Who is worthy to open the book,"], ["ma tatala ona faamaufaailoga?", "and to loose the seals thereof?"]]},
  {num:3,words:[["A e leai se tasi i le lagi,", "And no man in heaven,"], ["po o le lalolagi,", "nor in earth,"], ["po o lalo o le lalolagi,", "neither under the earth,"], ["na te mafaia ona fofolaina le tusi,", "was able to open the book,"], ["pe vaai i ai.", "neither to look thereon."]]},
  {num:4,words:[["Ona ou tagi tele ai lea,", "And I wept much,"], ["ina ua le maua se tasi e tatau ai ona fofolaina e ia ma faitau le tusi,", "because no man was found worthy to open and to read the book,"], ["pe vaai i ai.", "neither to look thereon."]]},
  {num:5,words:[["Ona fai mai ai lea ia te au o le tasi o le au toeaina,", "And one of the elders saith unto me,"], ["Aua e te tagi;", "Weep not:"], ["faauta,", "behold,"], ["ua manumalo le Leona o le itu aiga o Iuta,", "the Lion of the tribe of Juda,"], ["o le Aa o Tavita,", "the Root of David,"], ["e fofola i le tusi,", "hath prevailed to open the book,"], ["ma tatala i ona faamaufaailoga e fitu.", "and to loose the seven seals thereof."]]},
  {num:6,words:[["Na a'u iloa foi,", "And I beheld,"], ["faauta,", "and,"], ["ua tu mai i le va o le nofoālii ma mea ola e fa,", "lo,"], ["e i ona tua foi le au toeaina,", "in the midst of the throne and of the four beasts, and in the midst of the elders,"], ["o le Tamai mamoe e peiseai na fasia,", "stood a Lamb as it had been slain,"], ["e fitu ona nifo ma ona mata e fitu,", "having seven horns and seven eyes,"], ["o Agaga ia e toafitu o le Atua ua aauina atu i le lalolagi uma.", "which are the seven Spirits of God sent forth into all the earth."]]},
  {num:7,words:[["Ua alu atu ia, ma to mai le tusi mai le aao taumatau o lē tietie i le nofoālii.", "And he came and took the book out of the right hand of him that sat upon the throne."]]},
  {num:8,words:[["Ua to mai e ia le tusi,", "And when he had taken the book,"], ["ona faapaū ai lea o mea ola e fa ma toeaina e toaluafulu ma le toafa i luma o le Tamai mamoe,", "the four beasts and four and twenty elders fell down before the Lamb,"], ["ua tofu i latou ma le kitara,", "having every one of them harps,"], ["ma le ipu auro ua tumu i mea manogi e mu,", "and golden vials full of odours,"], ["o talosaga ia a le au paia;", "which are the prayers of saints."]]},
  {num:9,words:[["ua latou pepese foi i le pese fou,", "And they sung a new song,"], ["ua faapea atu,", "saying,"], ["Ua tatau lava oe ina ia e tago i le tusi,", "Thou art worthy to take the book,"], ["ma tatala i ona faamaufaailoga;", "and to open the seals thereof:"], ["auā na fasia oe, ua e faatauina foi i matou i lou lava toto mo le Atua,", "for thou wast slain,"], ["mai itu aiga uma,", "and hast redeemed us to God by thy blood out of every kindred,"], ["ma gagana eseese,", "and tongue,"], ["ma nuu,", "and people,"], ["atoa ma atu nuu;", "and nation;"]]},
  {num:10,words:[["ua faia foi e oe i matou ma tupu ma faitaulaga i lo matou Atua;", "And hast made us unto our God kings and priests:"], ["e fai foi i matou ma tupu i le lalolagi.", "and we shall reign on the earth."]]},
  {num:11,words:[["Na a'u iloa atu foi, ma ou faalogo i le leo o agelu e toatele,", "And I beheld,"], ["o e ua faataaliolio i le nofoālii,", "and I heard the voice of many angels round about the throne and the beasts and the elders:"], ["ma le leo o mea ola e fa atoa ma le au toeaina;", "and the number of them was ten thousand times ten thousand,"], ["o lo latou faitau aofai ua mano ni mano, ma afe ni afe,", "and thousands of thousands;"]]},
  {num:12,words:[["o loo faapea atu ma le leo tele,", "Saying with a loud voice,"], ["Ua tatau lava le Tamai mamoe na fasia ina ia tuuina atu ia te ia le mana,", "Worthy is the Lamb that was slain to receive power,"], ["ma le oa,", "and riches,"], ["ma le poto,", "and wisdom,"], ["ma le malosi,", "and strength,"], ["ma le faaneeneega,", "and honour,"], ["ma le viiga,", "and glory,"], ["ma le faamanū.", "and blessing."]]},
  {num:13,words:[["Na ou faalogo foi i mea uma na faia o i le lagi,", "And every creature which is in heaven,"], ["ma le lalolagi,", "and on the earth,"], ["ma lalo ifo o le lalolagi,", "and under the earth, and such as are in the sea,"], ["ma mea foi o i le sami,", "and all that are in them,"], ["atoa ma mea uma o i ai i ia mea,", "heard I saying,"], ["o loo faapea atu,", "Blessing,"], ["Ia ia te ia o lē tietie i le nofoālii atoa ma le Tamai mamoe le faamanū,", "and honour,"], ["ma le faaneeneega,", "and glory, and power,"], ["ma le viiga,", "be unto him that sitteth upon the throne,"], ["ma le malosi e faavavau faavavau lava.", "and unto the Lamb for ever and ever."]]},
  {num:14,words:[["Ona fai atu lea o mea ola e fa, Amene;", "And the four beasts said,"], ["ona faapaū lea o toeaina e toaluafulu ma le toafa ma ifo atu i lē soifua e faavavau e faavavau lava.", "Amen. And the four and twenty elders fell down and worshipped him that liveth for ever and ever."]]},
];
renderVerseSet(rev_ch_5_Verses, 'rev-ch5-verses');

var rev_ch_6_Verses = [
  {num:1,words:[["Na a'u iloa atu foi ua tatalaina e le Tamai mamoe le tasi o faamaufaailoga,", "And I saw when the Lamb opened one of the seals,"], ["ona ou faalogo ai lea i le tasi o mea ola e fa,", "and I heard,"], ["ua leo i le faititili,", "as it were the noise of thunder,"], ["ua faapea mai,", "one of the four beasts saying,"], ["Sau ia ina vaai.", "Come and see."]]},
  {num:2,words:[["Ona ou vaai ai lea,", "And I saw,"], ["faauta foi, o le solofanua sinasina,", "and behold a white horse:"], ["ua i ai le aufana i loo tietie ai;", "and he that sat on him had a bow;"], ["ua avatu foi ia te ia le palealii;", "and a crown was given unto him:"], ["ona alu atu lea o ia, o loo manumalo,", "and he went forth conquering,"], ["o le a manumalo pea ia.", "and to conquer."]]},
  {num:3,words:[["Ua tatalaina foi e ia o lona lua o faamaufaailoga,", "And when he had opened the second seal,"], ["ona ou faalogo ai lea i lona lua o mea ola, o loo faapea mai,", "I heard the second beast say,"], ["Sau ia ina vaai.", "Come and see."]]},
  {num:4,words:[["Ona alu atu lea o le isi solofanua mūmū;", "And there went out another horse that was red:"], ["ua avatu foi le pule i loo tietie ai na te aveeseina le filemu i le lalolagi,", "and power was given to him that sat thereon to take peace from the earth,"], ["a e latou te fefasiai ai;", "and that they should kill one another:"], ["ua avatu foi ia te ia le pelu tele.", "and there was given unto him a great sword."]]},
  {num:5,words:[["Ua tatalaina foi e ia o lona tolu o faamaufaailoga,", "And when he had opened the third seal,"], ["ona ou faalogo ai lea i lona tolu o mea ola, o loo faapea mai,", "I heard the third beast say,"], ["Sau ia ina vaai.", "Come and see."], ["Ona ou vaai lea,", "And I beheld,"], ["faauta foi, o le solofanua uliuli;", "and lo a black horse;"], ["ua i le lima o loo tietie ai le fua faatautau.", "and he that sat on him had a pair of balances in his hand."]]},
  {num:6,words:[["Na ou faalogo foi i le leo mai le va o mea ola e fa,", "And I heard a voice in the midst of the four beasts say,"], ["ua faapea mai,", "A measure of wheat for a penny,"], ["O le tau o le koini o le saito o le tenari lea, o le tau o koini e tolu o le karite o le tenari foi lea;", "and three measures of barley for a penny;"], ["a e aua e te faaleaga i le suāuu ma le uaina.", "and see thou hurt not the oil and the wine."]]},
  {num:7,words:[["Ua tatalaina foi e ia o lona fa o faamaufaailoga,", "And when he had opened the fourth seal,"], ["ona ou faalogo ai lea i le leo o lona fa o mea ola, ua faapea mai,", "I heard the voice of the fourth beast say,"], ["Sau ia ina vaai.", "Come and see."]]},
  {num:8,words:[["Ona ou vaai lea,", "And I looked,"], ["faauta,", "and behold a pale horse:"], ["o le solofanua samasama, ma lē tietie ai,", "and his name that sat on him was Death,"], ["o lona igoa o le Oti,", "and Hell followed with him. And power was given unto them over the fourth part of the earth,"], ["ua mulimuli atu foi Seoli ia te ia;", "to kill with sword,"], ["ua avatu foi ia te i laua le pule e fasioti i lona fa o vaega o le lalolagi i le pelu, ma le oge,", "and with hunger,"], ["ma le oti,", "and with death,"], ["atoa ma manu feai o le vao.", "and with the beasts of the earth."]]},
  {num:9,words:[["Ua tatalaina foi e ia o lona lima o faamaufaailoga,", "And when he had opened the fifth seal,"], ["ona ou iloa lea o i lalo ifo o le fata faitaulaga o agaga o e na fasiotia ona o le afioga a le Atua,", "I saw under the altar the souls of them that were slain for the word of God,"], ["ma le mau na latou taofi mau ai;", "and for the testimony which they held:"]]},
  {num:10,words:[["ua latou alalaga foi ma le leo tele,", "And they cried with a loud voice, saying,"], ["ua faapea atu,", "How long,"], ["Le Alii e,", "O Lord,"], ["le paia ma le faamaoni e te le faamasino ea ma taui i lo matou toto i e nonofo i le lalolagi seia afea?", "holy and true, dost thou not judge and avenge our blood on them that dwell on the earth?"]]},
  {num:11,words:[["Ua foaiina atu ia te i latou taitoatasi ofu sisina;", "And white robes were given unto every one of them; and it was said unto them,"], ["ua fai atu foi ia te i latou ia latou faatalitali lemu seia toe itiiti,", "that they should rest yet for a little season,"], ["seia atoatoa mai ai o latou uso a auauna atoa ma o latou uso,", "until their fellowservants also and their brethren,"], ["o le a fasiotia pei o i latou lava.", "that should be killed as they were, should be fulfilled."]]},
  {num:12,words:[["Na a'u iloa atu foi ua tatalaina e ia o lona ono o faamaufaailoga,", "And I beheld when he had opened the sixth seal,"], ["faauta foi,", "and,"], ["o le mafuie tele,", "lo, there was a great earthquake;"], ["o le la foi ua liua ua uliuli e pei o le ie fulufulu talatala,", "and the sun became black as sackcloth of hair,"], ["o le masina foi ua liua e pei o le toto,", "and the moon became as blood;"]]},
  {num:13,words:[["o fetu foi o le lagi ua pauu i le lalolagi,", "And the stars of heaven fell unto the earth, even as a fig tree casteth her untimely figs,"], ["e pei o le mati ona toulu o ona fua moto pe a luluina e le matagi tetele;", "when she is shaken of a mighty wind."]]},
  {num:14,words:[["ua mavae atu foi le lagi pei o se tusi ua taaia,", "And the heaven departed as a scroll when it is rolled together;"], ["o mauga ma motu uma foi ua aveeseina i mea sa i ai;", "and every mountain and island were moved out of their places."]]},
  {num:15,words:[["o tupu foi o le lalolagi,", "And the kings of the earth,"], ["ma alii sili,", "and the great men,"], ["ma e ua tamaoaiga,", "and the rich men,"], ["ma ta'ita'i o 'au e taitoaafe,", "and the chief captains, and the mighty men,"], ["ma e ua malolosi,", "and every bondman,"], ["ma pologa uma,", "and every free man,"], ["atoa ma tama a le eleele uma ua latou lalafi i ana ma papa o mauga;", "hid themselves in the dens and in the rocks of the mountains;"]]},
  {num:16,words:[["ua latou fai atu foi i mauga ma papa,", "And said to the mountains and rocks,"], ["Mafuli mai ia ia te i matou,", "Fall on us,"], ["ma tanumai i matou ai le silafaga a lē tietie i le nofoālii,", "and hide us from the face of him that sitteth on the throne,"], ["ma le toasa o le Tamai mamoe;", "and from the wrath of the Lamb:"]]},
  {num:17,words:[["auā ua oo mai le aso tele o lona toasa,", "For the great day of his wrath is come;"], ["o ai foi se na te mafaia ona tu atu?", "and who shall be able to stand?"]]},
];
renderVerseSet(rev_ch_6_Verses, 'rev-ch6-verses');

var rev_ch_7_Verses = [
  {num:1,words:[["Ua mavae atu ia mea,", "And after these things I saw four angels standing on the four corners of the earth,"], ["ona a'u iloa ai lea o agelu e toafa o tutū mai i itu e fa o le lalolagi,", "holding the four winds of the earth,"], ["o taofi i matagi e fa o le lalolagi, ina ia le agi atu le matagi i le fanua,", "that the wind should not blow on the earth,"], ["po o le sami,", "nor on the sea,"], ["po o se laau e tasi.", "nor on any tree."]]},
  {num:2,words:[["Ua a'u iloa foi le tasi agelu ua ui ae i le mea e alu ae ai le la,", "And I saw another angel ascending from the east,"], ["ua ia te ia le faamaufaailoga a le Atua soifua;", "having the seal of the living God: and he cried with a loud voice to the four angels,"], ["ua alaga ia ma le leo tele i agelu e toafa na tuuina atu ia i latou ia faaleaga i le fanua ma le sami,", "to whom it was given to hurt the earth and the sea,"]]},
  {num:3,words:[["ua faapea atu,", "Saying,"], ["Aua tou te faaleaga i le fanua,", "Hurt not the earth,"], ["po o le sami,", "neither the sea,"], ["po o laau,", "nor the trees,"], ["seia matou faamaufaailogaina auauna a lo tatou Atua i o latou muaulu.", "till we have sealed the servants of our God in their foreheads."]]},
  {num:4,words:[["Na ou faalogo foi i le faitau aofai o e na faamaufaailogaina;", "And I heard the number of them which were sealed:"], ["e selau afe ma afe e fagafulu ma afe e fa o e ua faamaufaailogaina i itu aiga uma o le fanauga a Isaraelu;", "and there were sealed an hundred and forty and four thousand of all the tribes of the children of Israel."]]},
  {num:5,words:[["e sefulu afe ma afe e lua o e ua faamaufaailogaina i le itu aiga o Iuta; e sefulu afe ma afe e lua o e ua faamaufaailogaina i le itu aiga o Reupena; e sefulu afe ma afe e lua o e ua faamaufaailogaina i le itu aiga o Kato;", "Of the tribe of Juda were sealed twelve thousand. Of the tribe of Reuben were sealed twelve thousand. Of the tribe of Gad were sealed twelve thousand."]]},
  {num:6,words:[["e sefulu afe ma afe e lua o e ua faamaufaailogaina i le itu aiga o Asera; e sefulu afe ma afe e lua o e ua faamaufaailogaina i le itu aiga o Nafatali; e sefulu afe ma afe e lua o e ua faamaufaailogaina i le itu aiga o Manase;", "Of the tribe of Aser were sealed twelve thousand. Of the tribe of Nepthalim were sealed twelve thousand. Of the tribe of Manasses were sealed twelve thousand."]]},
  {num:7,words:[["e sefulu afe ma afe e lua o e ua faamaufaailogaina i le itu aiga o Simeona; e sefulu afe ma afe e lua o e ua faamaufaailogaina i le itu aiga o Levi; e sefulu afe ma afe e lua o e ua faamaufaailogaina i le itu aiga o Isakara;", "Of the tribe of Simeon were sealed twelve thousand. Of the tribe of Levi were sealed twelve thousand. Of the tribe of Issachar were sealed twelve thousand."]]},
  {num:8,words:[["e sefulu afe ma afe e lua o e ua faamaufaailogaina i le itu aiga o Sepulona; e sefulu afe ma afe e lua o e ua faamaufaailogaina i le itu aiga i Iosefa; e sefulu afe ma afe e lua o e ua faamaufaailogaina i le itu aiga o Peniamina.", "Of the tribe of Zabulon were sealed twelve thousand. Of the tribe of Joseph were sealed twelve thousand. Of the tribe of Benjamin were sealed twelve thousand."]]},
  {num:9,words:[["Ua mavae atu ia mea,", "After this I beheld,"], ["ona ou iloa lea,", "and, lo,"], ["faauta foi i le motu o tagata e toatele mai atu nuu uma,", "a great multitude,"], ["ma aiga,", "which no man could number,"], ["ma nuu,", "of all nations,"], ["ma gagana eseese,", "and kindreds, and people,"], ["e le ma faitaulia e se tasi,", "and tongues,"], ["o loo tutū i latou i luma o le nofoālii ma luma o le Tamai mamoe,", "stood before the throne,"], ["ua oofu i latou i ofu sisina,", "and before the Lamb, clothed with white robes,"], ["ua i ai foi lau pama i o latou lima;", "and palms in their hands;"]]},
  {num:10,words:[["ua latou alalaga foi ma leo tetele,", "And cried with a loud voice,"], ["ua faapea atu,", "saying,"], ["O i ai le faaolataga i lo tatou Atua o lē tietie i le nofoālii,", "Salvation to our God which sitteth upon the throne,"], ["atoa ma le Tamai mamoe.", "and unto the Lamb."]]},
  {num:11,words:[["Ua tutū faataaliolio agelu uma i le nofoālii ma le au toeaina ma mea ola e fa,", "And all the angels stood round about the throne,"], ["ua latou faapaū fao i luma o le nofoālii,", "and about the elders and the four beasts, and fell before the throne on their faces,"], ["ma ifo atu i le Atua,", "and worshipped God,"]]},
  {num:12,words:[["ua faapea atu,", "Saying,"], ["Amene;", "Amen:"], ["Ia i lo tatou Atua le faamanū,", "Blessing,"], ["ma le viiga,", "and glory,"], ["ma le poto,", "and wisdom, and thanksgiving,"], ["ma le faafetai,", "and honour,"], ["ma le mamalu,", "and power,"], ["ma le mana,", "and might,"], ["ma le malosi e faavavau faavavau lava.", "be unto our God for ever and ever."], ["Amene.", "Amen."]]},
  {num:13,words:[["Ona fai mai ai lea o le tasi o le au toeaina, ua faapea mai ia te au,", "And one of the elders answered,"], ["O i latou ia e ua oofu i ofu sisina,", "saying unto me,"], ["o ai ea i latou, po o fea foi na latou o mai ai?", "What are these which are arrayed in white robes? and whence came they?"]]},
  {num:14,words:[["Ona ou faapea atu ai lea ia te ia,", "And I said unto him,"], ["Le Alii e,", "Sir,"], ["ua e silafia. Ona faapea mai ai lea o ia ia te au,", "thou knowest. And he said to me,"], ["O i latou ia o e o mai nai le puapuaga tele,", "These are they which came out of great tribulation,"], ["ua ta foi o latou ofu,", "and have washed their robes,"], ["ma ua faasinasinaina o latou ofu i le toto o le Tamai mamoe.", "and made them white in the blood of the Lamb."]]},
  {num:15,words:[["O le mea lea ua latou i luma ai o le nofoālii o le Atua,", "Therefore are they before the throne of God,"], ["ua latou auauna foi ia te ia i lona malumalu i le ao ma le po;", "and serve him day and night in his temple:"], ["o lē tietie foi i le nofoālii e mau ma i latou.", "and he that sitteth on the throne shall dwell among them."]]},
  {num:16,words:[["Latou te le toe fia aai,", "They shall hunger no more,"], ["e le toe fia inu foi e le ogotia i latou i le la,", "neither thirst any more; neither shall the sun light on them,"], ["po o se tasi vevela;", "nor any heat."]]},
  {num:17,words:[["auā o le Tamai mamoe o loo i luma o le nofoālii na te fafaga ia i latou,", "For the Lamb which is in the midst of the throne shall feed them,"], ["ma ta'ita'i ia te i latou i puna o vai ola;", "and shall lead them unto living fountains of waters:"], ["e sōloieseina foi e le Atua o loimata uma nai o latou mata.", "and God shall wipe away all tears from their eyes."]]},
];
renderVerseSet(rev_ch_7_Verses, 'rev-ch7-verses');

var rev_ch_8_Verses = [
  {num:1,words:[["Ua tatalaina foi e ia o lona fitu o faamaufaailoga,", "And when he had opened the seventh seal,"], ["ona lologo ai lea o e i le lagi pe atoa le vaeluagalemu o le itu aso e tasi.", "there was silence in heaven about the space of half an hour."]]},
  {num:2,words:[["Na a'u iloa foi agelu e toafitu o e tutū i luma o le Atua,", "And I saw the seven angels which stood before God;"], ["ua avatu foi ia te i latou pu e fitu.", "and to them were given seven trumpets."]]},
  {num:3,words:[["Ua sau foi le tasi agelu,", "And another angel came and stood at the altar,"], ["ma tu mai i le fata faitaulaga,", "having a golden censer;"], ["ua ia te ia le ipu auro e faamu ai mea manogi; ua avatu ia te ia mea manogi e tele,", "and there was given unto him much incense,"], ["ina ia avatu ai atoa ma talosaga a le au paia uma i luga o le fata auro ua i luma o le nofoālii.", "that he should offer it with the prayers of all saints upon the golden altar which was before the throne."]]},
  {num:4,words:[["O le asu foi o le mea manogi ua i le lima o le agelu ua alu ae,", "And the smoke of the incense,"], ["atoa ma talosaga a le au paia,", "which came with the prayers of the saints,"], ["i luma o le Atua.", "ascended up before God out of the angel's hand."]]},
  {num:5,words:[["Ua tago foi le agelu i le ipu e faamu ai mea manogi,", "And the angel took the censer,"], ["ua ia faatumuina ai i le afi ai le fata faitaulaga,", "and filled it with fire of the altar,"], ["ua lafo ifo ai i le lalolagi;", "and cast it into the earth:"], ["ona i ai lea o leo,", "and there were voices,"], ["ma faititili,", "and thunderings,"], ["ma uila,", "and lightnings,"], ["ma le mafuie.", "and an earthquake."]]},
  {num:6,words:[["O agelu e toafitu ua i ai pu e fitu, ua latou sauniuni e ili.", "And the seven angels which had the seven trumpets prepared themselves to sound."]]},
  {num:7,words:[["Ua ili foi e le agelu muamua le pu,", "The first angel sounded,"], ["ona i ai lea o le uato'a ma le afi ua fefiloi ma le toto,", "and there followed hail and fire mingled with blood,"], ["ua lafo ifo i le lalolagi;", "and they were cast upon the earth:"], ["ona susunuina ai lea o lona tolu o vaega o laau,", "and the third part of trees was burnt up,"], ["ma ua susunuina vao iti lauolaola uma lava.", "and all green grass was burnt up."]]},
  {num:8,words:[["Ua ili foi e lona toalua o agelu le pu,", "And the second angel sounded,"], ["ona i ai lea peiseai se mauga tele ua mu i le afi, ua lafo ifo i le sami;", "and as it were a great mountain burning with fire was cast into the sea:"], ["ona liu toto lea o lona tolu o vaega o le sami.", "and the third part of the sea became blood;"]]},
  {num:9,words:[["Ona mamate ai lea o lona tolu o vaega o mea ola o i le sami,", "And the third part of the creatures which were in the sea, and had life,"], ["atoa ma lona tolu o vaega o vaa ua faaumatia.", "died; and the third part of the ships were destroyed."]]},
  {num:10,words:[["Ua ili foi e lona toatolu o agelu le pu,", "And the third angel sounded,"], ["ona paū ai lea nai le lagi o le fetu tele,", "and there fell a great star from heaven,"], ["ua mu e pei o se lamepa,", "burning as it were a lamp,"], ["ma ua paū ifo i lona tolu o vaega o vaitafe,", "and it fell upon the third part of the rivers,"], ["atoa ma puna o vai.", "and upon the fountains of waters;"]]},
  {num:11,words:[["Ua igoa le fetu o le Oona;", "And the name of the star is called Wormwood:"], ["ona faaoonaina ai lea o lona tolu o vaega o vai,", "and the third part of the waters became wormwood;"], ["ua oti foi tagata e toatele i le vai,", "and many men died of the waters,"], ["ina ua faaoonaina.", "because they were made bitter."]]},
  {num:12,words:[["Ua ili foi e lona toafa o agelu le pu,", "And the fourth angel sounded,"], ["ona taia ai lea o lona tolu o vaega o le la,", "and the third part of the sun was smitten,"], ["ma lona tolu o vaega o le masina,", "and the third part of the moon,"], ["atoa ma lona tolu o vaega o fetu,", "and the third part of the stars;"], ["ina ia faapouliuligia o lona taitolu o latou vaega,", "so as the third part of them was darkened,"], ["e lei malamalama foi o lona tolu o vaega o le ao,", "and the day shone not for a third part of it,"], ["ua faapea foi ma le po.", "and the night likewise."]]},
  {num:13,words:[["Na ou iloa,", "And I beheld,"], ["ma ou faalogo i le tasi agelu ua lele i le taulotoaiga o le lagi,", "and heard an angel flying through the midst of heaven,"], ["ua faapea mai ma le leo tele,", "saying with a loud voice,"], ["Aue,", "Woe, woe,"], ["aue,", "woe,"], ["aue i e o nonofo i le lalolagi,", "to the inhabiters of the earth by reason of the other voices of the trumpet of the three angels,"], ["ona o isi iligāpu a agelu e toatolu o le a ilia mai.", "which are yet to sound!"]]},
];
renderVerseSet(rev_ch_8_Verses, 'rev-ch8-verses');

var rev_ch_9_Verses = [
  {num:1,words:[["Ua ili foi e lona toalima o agelu le pu,", "And the fifth angel sounded,"], ["ona ou iloa ai lea o le fetu ua paū nai le lagi i le lalolagi;", "and I saw a star fall from heaven unto the earth:"], ["ua tuuina atu foi ia te ia le ki o le to e le gata.", "and to him was given the key of the bottomless pit."]]},
  {num:2,words:[["Ua tatala foi e ia le to e le gata;", "And he opened the bottomless pit;"], ["ona alu ae ai lea o le asu ai le to e pei o le asu o se umu tele,", "and there arose a smoke out of the pit, as the smoke of a great furnace;"], ["ua faapouliuligia ai le la ma le lagi ona o le asu o le to.", "and the sun and the air were darkened by reason of the smoke of the pit."]]},
  {num:3,words:[["Ua o atu foi sē akerisi nai le asu i luga o le laueleele;", "And there came out of the smoke locusts upon the earth: and unto them was given power,"], ["ua tuuina atu ia te i latou le malosi e pei o le malosi o akarava o le vao;", "as the scorpions of the earth have power."]]},
  {num:4,words:[["ua fai atu foi ia te i latou aua ne'i latou faaleaga i vao iti o le fanua,", "And it was commanded them that they should not hurt the grass of the earth,"], ["po o se mea lauolaola e tasi,", "neither any green thing,"], ["po o se laau e tasi;", "neither any tree;"], ["tau lava o tagata ua le i ai i o latou muaulu le faamaufaailoga a le Atua.", "but only those men which have not the seal of God in their foreheads."]]},
  {num:5,words:[["Ua tuuina atu ia te i latou aua ne'i fasiotia i latou,", "And to them it was given that they should not kill them,"], ["tau lava ina faatigaina i masina e lima;", "but that they should be tormented five months: and their torment was as the torment of a scorpion,"], ["o latou tiga foi e pei o le tiga o le tagata pe a tuia e le akarava.", "when he striketh a man."]]},
  {num:6,words:[["O ona po ia e saili ai e tagata le oti,", "And in those days shall men seek death,"], ["a e latou te le maua;", "and shall not find it;"], ["e naunau foi i latou ina ia oti,", "and shall desire to die,"], ["a e sola ese le oti ia te i latou.", "and death shall flee from them."]]},
  {num:7,words:[["O sē akerisi foi ua tino mai e pei o solofanua ua saunia i le taua;", "And the shapes of the locusts were like unto horses prepared unto battle;"], ["o latou ulu foi ua peiseai ua i ai palealii e pei o auro,", "and on their heads were as it were crowns like gold,"], ["ma o latou mata e pei o mata o tagata;", "and their faces were as the faces of men."]]},
  {num:8,words:[["ua ia te i latou foi lauulu e pei o lauulu o fafine,", "And they had hair as the hair of women,"], ["ma o latou nifo e pei o nifo o leona;", "and their teeth were as the teeth of lions."]]},
  {num:9,words:[["ua ia te i latou foi ufifatafata e pei o ufifatafata uamea;", "And they had breastplates, as it were breastplates of iron;"], ["ua palalu foi o latou apaau e pei o le taalili o kariota ma solofanua e tele pe a taufetuli e tau.", "and the sound of their wings was as the sound of chariots of many horses running to battle."]]},
  {num:10,words:[["Ua ia te i latou o iu e pei o iu o akarava,", "And they had tails like unto scorpions,"], ["ua i ai foi tui i o latou iu;", "and there were stings in their tails:"], ["ma ua ia te i latou le malosi e faaleaga ai tagata i masina e lima.", "and their power was to hurt men five months."]]},
  {num:11,words:[["Ua ia te i latou foi le tupu,", "And they had a king over them,"], ["o le agelu lea o le to e le gata;", "which is the angel of the bottomless pit,"], ["o lona igoa i le upu Eperu o Avatonu,", "whose name in the Hebrew tongue is Abaddon,"], ["a o lona igoa i le upu Eleni o Apoluonu.", "but in the Greek tongue hath his name Apollyon."]]},
  {num:12,words:[["Ua mavae atu le aue e tasi;", "One woe is past;"], ["faauta,", "and, behold,"], ["ua totoe aue e lua e mulimuli ane i le oo mai.", "there come two woes more hereafter."]]},
  {num:13,words:[["Ua ili foi e lona toaono o agelu le pu,", "And the sixth angel sounded,"], ["ona ou faalogo ai lea i le leo mai nifo e fa o le fata auro o i luma o le Atua,", "and I heard a voice from the four horns of the golden altar which is before God,"]]},
  {num:14,words:[["ua faapea atu i lona toaono o agelu ua i ai le pu. Tatala ia agelu e toafa o e ua fusifusia i le vaitafe tele o Eufirate.", "Saying to the sixth angel which had the trumpet, Loose the four angels which are bound in the great river Euphrates."]]},
  {num:15,words:[["Ona talatalaina ai lea o ia agelu e toafa o e ua saunia i le itu aso,", "And the four angels were loosed,"], ["ma le aso,", "which were prepared for an hour,"], ["ma le masina,", "and a day, and a month,"], ["ma le tausaga,", "and a year,"], ["ina ia latou fasiotia lona tolu o vaega o tagata.", "for to slay the third part of men."]]},
  {num:16,words:[["O le faitau aofai o le 'au tau o e ua tietie i solofanua e lua mano o mano;", "And the number of the army of the horsemen were two hundred thousand thousand:"], ["ua ou faalogo foi i le faitau aofai o i latou.", "and I heard the number of them."]]},
  {num:17,words:[["E faapea foi ona a'u iloa o solofanua i le mea na vaaia,", "And thus I saw the horses in the vision,"], ["ma e ua tietie ai, ua i ai ufifatafata afi,", "and them that sat on them,"], ["ma le uakini,", "having breastplates of fire,"], ["ma le teio;", "and of jacinth,"], ["o ulu foi o solofanua e pei o ulu o leona,", "and brimstone:"], ["ua alu atu nai o latou gutu le afi, ma le asu,", "and the heads of the horses were as the heads of lions;"], ["ma le teio.", "and out of their mouths issued fire and smoke and brimstone."]]},
  {num:18,words:[["O mea ia e tolu na fasiotia ai lona tolu o vaega o tagata,", "By these three was the third part of men killed,"], ["o le afi,", "by the fire,"], ["ma le asu,", "and by the smoke, and by the brimstone,"], ["ma le teio na alu atu nai o latou gutu.", "which issued out of their mouths."]]},
  {num:19,words:[["Auā ua i o latou gutu ma o latou iu lo latou malosi;", "For their power is in their mouth,"], ["auā o latou iu e pei o gata ia,", "and in their tails:"], ["ua i ai ulu,", "for their tails were like unto serpents, and had heads,"], ["o mea foi ia latou te faaleaga ai tagata .", "and with them they do hurt."]]},
  {num:20,words:[["O tagata foi na totoe o e lei fasiotia i nei mala,", "And the rest of the men which were not killed by these plagues yet repented not of the works of their hands,"], ["latou te lei salamo i galuega a o latou lima,", "that they should not worship devils,"], ["o lo latou ifo i temoni,", "and idols of gold,"], ["ma tupua auro,", "and silver,"], ["ma ario, ma 'apa memea,", "and brass,"], ["ma maa,", "and stone,"], ["ma laau,", "and of wood:"], ["o mea ia e le mafaia ona vaai,", "which neither can see,"], ["pe faalogo,", "nor hear,"], ["pe savavali;", "nor walk:"]]},
  {num:21,words:[["latou te lei salamo foi i o latou fasioti tagata,", "Neither repented they of their murders,"], ["ma a latou togafiti faataulāitu,", "nor of their sorceries,"], ["ma la latou faitaaga,", "nor of their fornication,"], ["ma o latou gaoi.", "nor of their thefts."]]},
];
renderVerseSet(rev_ch_9_Verses, 'rev-ch9-verses');

var rev_ch_10_Verses = [
  {num:1,words:[["Na a'u iloa atu foi le tasi agelu malosi ua alu ifo mai le lagi,", "And I saw another mighty angel come down from heaven,"], ["ua ofu i le ao,", "clothed with a cloud:"], ["ua i lona ulu le nuanua,", "and a rainbow was upon his head,"], ["o ona fofoga foi e pei o le la,", "and his face was as it were the sun,"], ["o ona vae foi e pei o pou tu afi;", "and his feet as pillars of fire:"]]},
  {num:2,words:[["ua i lona lima foi le tusi itiiti ua fofola;", "And he had in his hand a little book open:"], ["ua tu lona vae taumatau i le sami,", "and he set his right foot upon the sea,"], ["ma lona vae tauagavale i le fanua,", "and his left foot on the earth,"]]},
  {num:3,words:[["ua alaga foi ia ma le leo tele,", "And cried with a loud voice,"], ["e pei o le leona pe a tagi;", "as when a lion roareth:"], ["ua alaga ia,", "and when he had cried,"], ["ona feganavai mai ai lea o faititili e fitu i o latou lava leo;", "seven thunders uttered their voices."]]},
  {num:4,words:[["ua feganavai mai faititili e fitu i o latou lava leo,", "And when the seven thunders had uttered their voices,"], ["na fai a a'u tusia;", "I was about to write:"], ["ona ou faalogo ai lea i le leo mai le lagi, ua faapea mai ia te au,", "and I heard a voice from heaven saying unto me,"], ["Ina faamaufaailogaina ia o na mea na feganavai mai ai o faititili e fitu,", "Seal up those things which the seven thunders uttered,"], ["aua ne'i e tusia na mea.", "and write them not."]]},
  {num:5,words:[["O le agelu foi na iloa e a'u ua tu i le sami ma le fanua, ua sii ae e ia lona lima i le lagi,", "And the angel which I saw stand upon the sea and upon the earth lifted up his hand to heaven,"]]},
  {num:6,words:[["ma ua tauto i le o soifua e faavavau faavavau lava,", "And sware by him that liveth for ever and ever, who created heaven,"], ["o le na faia le lagi ma mea o i ai,", "and the things that therein are,"], ["ma le fanua ma mea o i ai,", "and the earth, and the things that therein are,"], ["ma le sami ma mea o i ai,", "and the sea,"], ["e le toe ai ni aso;", "and the things which are therein, that there should be time no longer:"]]},
  {num:7,words:[["a e peitai a oo i ia ona po o le leo o lona toafitu o agelu,", "But in the days of the voice of the seventh angel,"], ["pe a ilia e ia le pu,", "when he shall begin to sound,"], ["ona taunuu ai lea o le mea lilo a le Atua,", "the mystery of God should be finished,"], ["e pei ona folafolaina mai e ia i ana auauna le au perofeta.", "as he hath declared to his servants the prophets."]]},
  {num:8,words:[["O le leo foi na ou faalogo ai mai le lagi, ua toe tautala mai ia te au,", "And the voice which I heard from heaven spake unto me again,"], ["ua faapea mai, Alu ia,", "and said,"], ["ina tago i le tusi itiiti ua fofola, o i le lima o le agelu o loo tu i le sami ma le fanua.", "Go and take the little book which is open in the hand of the angel which standeth upon the sea and upon the earth."]]},
  {num:9,words:[["Ona ou alu atu ai lea i le agelu,", "And I went unto the angel,"], ["ma ou fai atu ia te ia,", "and said unto him,"], ["Au mai ia te au le tusi itiiti. Ona faapea mai ai lea o ia ia te au,", "Give me the little book. And he said unto me,"], ["Ina tago ia i ai,", "Take it,"], ["ma e 'aina;", "and eat it up;"], ["e oona i lou manava,", "and it shall make thy belly bitter,"], ["a e suamalie i lou gutu e pei o le meli.", "but it shall be in thy mouth sweet as honey."]]},
  {num:10,words:[["Ona ou tago ai lea i le tusi itiiti nai le lima o le agelu,", "And I took the little book out of the angel's hand,"], ["ma a'u 'aina;", "and ate it up;"], ["ona suamalie ai lea i lo'u gutu e pei o le meli;", "and it was in my mouth sweet as honey:"], ["ua uma ona ou 'ai ai,", "and as soon as I had eaten it,"], ["ona oona lea i lo'u manava.", "my belly was bitter."]]},
  {num:11,words:[["Ona faapea mai ai lea o ia ia te au,", "And he said unto me,"], ["E ao ina e toe vavalo i nuu,", "Thou must prophesy again before many peoples,"], ["ma atu nuu,", "and nations,"], ["ma gagana eseese,", "and tongues,"], ["ma tupu e toatele.", "and kings."]]},
];
renderVerseSet(rev_ch_10_Verses, 'rev-ch10-verses');

var rev_ch_11_Verses = [
  {num:1,words:[["Ona tuuina mai lea ia te au le u e pei o se tootoo;", "And there was given me a reed like unto a rod:"], ["ua tu mai foi le agelu,", "and the angel stood,"], ["ua faapea mai,", "saying,"], ["Tulai ia,", "Rise,"], ["ina fuatia ia le malumalu o le Atua,", "and measure the temple of God,"], ["ma le fata faitaulaga,", "and the altar,"], ["ma e o tapuai i ai;", "and them that worship therein."]]},
  {num:2,words:[["a o le lotoā o le malumalu e aupito i tua,", "But the court which is without the temple leave out,"], ["lafoai lea,", "and measure it not;"], ["aua foi e te fuaina, auā ua tuuina atu i nuu ese;", "for it is given unto the Gentiles:"], ["latou te solia foi le aai paia i masina e fagafulu ma le lua.", "and the holy city shall they tread under foot forty and two months."]]},
  {num:3,words:[["Ou te tuuina atu foi i a'u molimau e toalua,", "And I will give power unto my two witnesses,"], ["la te vavalo ai i aso e tasi le afe e lua selau ma le onogafulu,", "and they shall prophesy a thousand two hundred and threescore days,"], ["o oofu i laua i ie talatala.", "clothed in sackcloth."]]},
  {num:4,words:[["O laau olive ia e lua,", "These are the two olive trees,"], ["ma tuugālamepa e lua ua tutū i luma o Atua o le lalolagi.", "and the two candlesticks standing before the God of the earth."]]},
  {num:5,words:[["Afai foi e fia faaleaga se tasi ia te i laua,", "And if any man will hurt them,"], ["ona alu atu ai lea o le afi ai o la gutu,", "fire proceedeth out of their mouth,"], ["e faaumatia ai e ua fai i laua mo latou fili;", "and devoureth their enemies:"], ["afai foi e fia faaleaga se tasi ia te i laua,", "and if any man will hurt them,"], ["e tusa ona faapea ona fasiotia o ia.", "he must in this manner be killed."]]},
  {num:6,words:[["Ua ia te i laua le pule e pupuni le lagi,", "These have power to shut heaven,"], ["ina ia le to ifo se ua i aso o la la valoaga;", "that it rain not in the days of their prophecy:"], ["ua ia i laua foi le pule i vai e liu ai ma toto,", "and have power over waters to turn them to blood,"], ["e taia foi le lalolagi i mala uma,", "and to smite the earth with all plagues,"], ["o lo la faitalia pe atu fia.", "as often as they will."]]},
  {num:7,words:[["Pe a uma ona la faaiuina la la mau,", "And when they shall have finished their testimony,"], ["ona sii mai lea o le taua ia te i laua e le manu feai le ua alu ae nai le to e le gata,", "the beast that ascendeth out of the bottomless pit shall make war against them,"], ["e manumalo foi o ia ia te i laua,", "and shall overcome them,"], ["ma fasioti ia te i laua.", "and kill them."]]},
  {num:8,words:[["O la tino foi e i ai ia i le ala o le aai tele,", "And their dead bodies shall lie in the street of the great city,"], ["o lona igoa faaleagaga, o Sotoma ma Aikupito,", "which spiritually is called Sodom and Egypt,"], ["o le mea foi na faasatauroina ai lo tatou Alii.", "where also our Lord was crucified."]]},
  {num:9,words:[["E tolu aso ma le vaeluagalemu o le aso e vaavaai ai i o la tino e nisi mai nuu, ma itu aiga,", "And they of the people and kindreds and tongues and nations shall see their dead bodies three days and an half,"], ["ma gagana eseese, ma atu nuu, a e latou te le mafafai ona ia tuuina atu o la tino i tuugamau.", "and shall not suffer their dead bodies to be put in graves."]]},
  {num:10,words:[["E fiafia foi e ua nonofo i le nuu ona o i laua,", "And they that dwell upon the earth shall rejoice over them,"], ["ma latou olioli,", "and make merry,"], ["ma feaveai mea alofa;", "and shall send gifts one to another;"], ["auā na faatigaina e ua nonofo i le nuu e ia perofeta e toalua.", "because these two prophets tormented them that dwelt on the earth."]]},
  {num:11,words:[["A ua mavae aso e tolu ma le vaeluagalemu o le aso,", "And after three days and an half the Spirit of life from God entered into them,"], ["ona uluitinoina ai lea o i laua e le Agaga ola mai le Atua, ona la tutū ai lea i luga i o la vae,", "and they stood upon their feet;"], ["ona oo ai lea o le mata'u tele i e na matamata ia te i laua.", "and great fear fell upon them which saw them."]]},
  {num:12,words:[["Ona la faalogo lea i le leo tele mai le lagi, ua faapea atu ia te i laua,", "And they heard a great voice from heaven saying unto them,"], ["Ina o mai ia i luga nei.", "Come up hither."], ["Ona la o ae ai lea i le lagi i le ao,", "And they ascended up to heaven in a cloud;"], ["ua matamata foi ia te i laua o e na fai i laua mo latou fili.", "and their enemies beheld them."]]},
  {num:13,words:[["O le itu aso lava lea na to ai le mafuie tele,", "And the same hour was there a great earthquake,"], ["ua paū ai foi lona sefulu o vaega o le aai,", "and the tenth part of the city fell,"], ["ua oti foi i le mafuie tagata e toafitugaafe;", "and in the earthquake were slain of men seven thousand:"], ["ua matatau foi e na totoe,", "and the remnant were affrighted,"], ["ona latou vivii atu lea i le Atua o le lagi.", "and gave glory to the God of heaven."]]},
  {num:14,words:[["Ua mavae atu lona lua o aue;", "The second woe is past;"], ["faauta,", "and, behold,"], ["o lona tolu o aue e vave ona oo mai.", "the third woe cometh quickly."]]},
  {num:15,words:[["Ua ili foi e lona toafitu o agelu le pu,", "And the seventh angel sounded;"], ["ona i ai lea i le lagi o leo tetele,", "and there were great voices in heaven,"], ["ua faapea mai,", "saying, The kingdoms of this world are become the kingdoms of our Lord,"], ["O malo o le lalolagi ua avea mo lo tatou Alii ma lona Keriso,", "and of his Christ;"], ["e fai foi o ia ma tupu e faavavau faavavau lava.", "and he shall reign for ever and ever."]]},
  {num:16,words:[["O toeaina foi e toaluafulu ma le toafa,", "And the four and twenty elders,"], ["o e nonofo i o latou nofoālii i luma o le Atua,", "which sat before God on their seats,"], ["ua latou faapaū fao,", "fell upon their faces,"], ["ma ifo i le Atua,", "and worshipped God,"]]},
  {num:17,words:[["ua faapea atu,", "Saying,"], ["Le Alii e,", "We give thee thanks,"], ["le Atua e ou le malosi uma lava,", "O Lord God Almighty,"], ["ua matou faafetai atu ia te oe,", "which art,"], ["o lē soifua,", "and wast,"], ["o le na soifua,", "and art to come;"], ["o le a afio mai,", "because thou hast taken to thee thy great power,"], ["ina ua e tago i lou mana tele ma ua fai oe ma tupu.", "and hast reigned."]]},
  {num:18,words:[["Ua ita foi nuu,", "And the nations were angry,"], ["ona oo mai lea o lou toasa,", "and thy wrath is come,"], ["ma ona po e faamasinoina ai e ua oti,", "and the time of the dead,"], ["ma taui ai i au auauna le au perofeta,", "that they should be judged,"], ["ma le au paia,", "and that thou shouldest give reward unto thy servants the prophets, and to the saints,"], ["ma e ua matatau i lou suafa,", "and them that fear thy name,"], ["o tagatānuu atoa ma alii,", "small and great;"], ["e fano ai foi i latou o e na fano ai le lalolagi.", "and shouldest destroy them which destroy the earth."]]},
  {num:19,words:[["Ua faaavanoaina foi le malumalu o le Atua i le lagi,", "And the temple of God was opened in heaven,"], ["ona iloa atu ai lea o le atolaau o lana feagaiga i lona malumalu;", "and there was seen in his temple the ark of his testament:"], ["ona tutupu lea o uila,", "and there were lightnings,"], ["ma leo,", "and voices,"], ["ma faititili,", "and thunderings,"], ["ma le mafuie,", "and an earthquake,"], ["ma le uato'a tetele.", "and great hail."]]},
];
renderVerseSet(rev_ch_11_Verses, 'rev-ch11-verses');

var rev_ch_12_Verses = [
  {num:1,words:[["Ua iloa foi le faailoga tele i le lagi,", "And there appeared a great wonder in heaven;"], ["o le fafine ua ofu i le la,", "a woman clothed with the sun,"], ["o i lalo o ona vae le masina,", "and the moon under her feet,"], ["o i lona ulu foi le palealii fetu e sefulu ma le lua;", "and upon her head a crown of twelve stars:"]]},
  {num:2,words:[["ua to foi o ia;", "And she being with child cried, travailing in birth,"], ["ua faatiga ma alaga i le tiga a fanau.", "and pained to be delivered."]]},
  {num:3,words:[["Ua iloa foi le tasi faailoga i le lagi,", "And there appeared another wonder in heaven;"], ["faauta foi,", "and behold a great red dragon,"], ["o le tarako tele e mūmū, e fitu ona ulu ma ona nifo e sefulu;", "having seven heads and ten horns,"], ["ua i ona ulu o palealii e fitu.", "and seven crowns upon his heads."]]},
  {num:4,words:[["Ua toso e lona iu i lona tolu o vaega o fetu i le lagi,", "And his tail drew the third part of the stars of heaven,"], ["ma lafo ifo ia i latou i le lalolagi. Ua tu foi le tarako i luma o le fafine o le a fanau,", "and did cast them to the earth: and the dragon stood before the woman which was ready to be delivered,"], ["ina ia 'ai e ia o lana tama pe a fanau.", "for to devour her child as soon as it was born."]]},
  {num:5,words:[["Ua fanau foi e ia o le tama tane,", "And she brought forth a man child,"], ["o le na te pule i nuu uma i le tootoo uamea;", "who was to rule all nations with a rod of iron: and her child was caught up unto God,"], ["ona segia ae lea o lana tama i le Atua i lona nofoālii.", "and to his throne."]]},
  {num:6,words:[["Ona sola lea o le fafine i le vao,", "And the woman fled into the wilderness,"], ["o i ai le mea ua saunia e le Atua e nofo ai o ia,", "where she hath a place prepared of God,"], ["ina ia latou fafaga ai ia te ia i aso e tasi le afe ma le lua o selau ma le onogafulu.", "that they should feed her there a thousand two hundred and threescore days."]]},
  {num:7,words:[["Ua tau foi le taua i le lagi;", "And there was war in heaven:"], ["o Mekaeli ma ana agelu ua latou tau ma le tarako,", "Michael and his angels fought against the dragon;"], ["ua 'au foi le tarako ma ana agelu e tau ai le taua,", "and the dragon fought and his angels,"]]},
  {num:8,words:[["a ua latou le manumalo,", "And prevailed not;"], ["e le toe maua foi i le lagi se mea latou te nonofo ai.", "neither was their place found any more in heaven."]]},
  {num:9,words:[["Ua lafo foi le tarako tele,", "And the great dragon was cast out,"], ["o le gata tuai lea,", "that old serpent,"], ["ua igoa i le tiapolo,", "called the Devil,"], ["i le ma Satani,", "and Satan,"], ["o lē faasese i le lalolagi uma;", "which deceiveth the whole world:"], ["ua lafo ifo i le lalolagi,", "he was cast out into the earth,"], ["ua lafo foi ana agelu faatasi ma ia.", "and his angels were cast out with him."]]},
  {num:10,words:[["Na ou faalogo foi i le leo tele i le lagi,", "And I heard a loud voice saying in heaven,"], ["ua faapea,", "Now is come salvation,"], ["O ona po nei ua oo mai ai le olataga,", "and strength,"], ["ma le mana,", "and the kingdom of our God,"], ["ma le malo o lo tatou Atua ma le pule a lona Keriso;", "and the power of his Christ:"], ["auā ua lafo i lalo le na molia o tatou uso,", "for the accuser of our brethren is cast down,"], ["o le na molia i latou i luma o lo tatou Atua i le ao ma le po.", "which accused them before our God day and night."]]},
  {num:11,words:[["A ua latou manumalo ia te ia ona o le toto o le Tamai mamoe,", "And they overcame him by the blood of the Lamb,"], ["ma le upu a la latou mau,", "and by the word of their testimony;"], ["ua latou le faapelepeleina foi lo latou ola ua oo i le oti.", "and they loved not their lives unto the death."]]},
  {num:12,words:[["O le mea lea ia outou olioli ai,", "Therefore rejoice, ye heavens,"], ["le lagi e atoa ma e ua nonofo ai.", "and ye that dwell in them."], ["O i talofa ia te outou o e nonofo i le fanua ma le sami,", "Woe to the inhabiters of the earth and of the sea! for the devil is come down unto you,"], ["auā ua alu ifo ia te outou le tiapolo ua lotoa tele,", "having great wrath,"], ["auā ua na iloa ua saasaa ona po.", "because he knoweth that he hath but a short time."]]},
  {num:13,words:[["Ua iloa e le tarako ua lafo ifo o ia i le lalolagi,", "And when the dragon saw that he was cast unto the earth,"], ["ona faasaua lea o ia i le fafine na na fanaua le tama tane.", "he persecuted the woman which brought forth the man child."]]},
  {num:14,words:[["Ona foaiina atu lea i le fafine apaau e lua o le aeto tele,", "And to the woman were given two wings of a great eagle,"], ["ina ia lele ai o ia ai luma o le gata i le vao i le mea e nofo ai o ia,", "that she might fly into the wilderness, into her place,"], ["e fagaina ai o ia i le tausaga,", "where she is nourished for a time,"], ["ma tausaga,", "and times, and half a time,"], ["ma lona vaeluagalemu o le tausaga.", "from the face of the serpent."]]},
  {num:15,words:[["Ona luai atu lea e le gata le vai, e pei o se vaitafe nai lona gutu i tua o le fafine,", "And the serpent cast out of his mouth water as a flood after the woman,"], ["ina ia tafea o ia i le vai.", "that he might cause her to be carried away of the flood."]]},
  {num:16,words:[["Ona fesoasoani ai lea o le fanua i le fafine,", "And the earth helped the woman,"], ["ua faamaga ae foi e le fanua lona gutu,", "and the earth opened her mouth,"], ["ma ua inu i le vaitafe ua luai atu e le tarako nai lona gutu.", "and swallowed up the flood which the dragon cast out of his mouth."]]},
  {num:17,words:[["Ua ita foi le tarako i le fafine,", "And the dragon was wroth with the woman,"], ["ona alu atu ai lea o ia e tau le taua ma i latou ua totoe o lana fanau,", "and went to make war with the remnant of her seed,"], ["o e ua tausi i poloaiga a le Atua,", "which keep the commandments of God,"], ["ma ua taofi le mau ia Iesu Keriso.", "and have the testimony of Jesus Christ."]]},
];
renderVerseSet(rev_ch_12_Verses, 'rev-ch12-verses');

var rev_ch_13_Verses = [
  {num:1,words:[["Ua ou tu i le oneone i le matafaga;", "And I stood upon the sand of the sea,"], ["ona a'u iloa ai lea o le manu feai ua alu ae nai le sami,", "and saw a beast rise up out of the sea,"], ["e fitu ona ulu ma ona nifo e sefulu;", "having seven heads and ten horns,"], ["ua i ona nifo foi o palealii e sefulu,", "and upon his horns ten crowns,"], ["ua i ona ulu foi o le igoa faifai.", "and upon his heads the name of blasphemy."]]},
  {num:2,words:[["O le manu feai foi na ou iloa,", "And the beast which I saw was like unto a leopard,"], ["e pei o le nameri,", "and his feet were as the feet of a bear,"], ["o ona vae foi e pei o vae o le urosa,", "and his mouth as the mouth of a lion:"], ["ma lona gutu e pei o le gutu o le leona. Ua tuuina atu foi ia te ia e le tarako lona malosi,", "and the dragon gave him his power,"], ["ma lona nofoālii,", "and his seat,"], ["ma le pule tele.", "and great authority."]]},
  {num:3,words:[["Na a'u iloa foi le tasi o ona ulu e peiseai ua foa a mate;", "And I saw one of his heads as it were wounded to death;"], ["a o lona foa na fai a mate ai ua mafu,", "and his deadly wound was healed:"], ["ona ofo ai lea o le lalolagi uma ma latou mulimuli atu i le manu feai.", "and all the world wondered after the beast."]]},
  {num:4,words:[["Ua latou ifo foi i le tarako o le na tuuina atu le pule i le manu feai,", "And they worshipped the dragon which gave power unto the beast:"], ["ua latou ifo foi i le manu feai,", "and they worshipped the beast, saying,"], ["ua faapea atu. O ai sē tusa ma le manu feai? O ai se na te mafaia ona tau ma ia?", "Who is like unto the beast? who is able to make war with him?"]]},
  {num:5,words:[["Ua avatu foi ia te ia le gutu e tautala ai i upu tetele ma upu faifai;", "And there was given unto him a mouth speaking great things and blasphemies;"], ["ua tuuina atu foi ia te ia le pule e tau ai le taua i masina e fagafulu ma le lua.", "and power was given unto him to continue forty and two months."]]},
  {num:6,words:[["Ona tautala lea o ia ua upu leaga i le Atua,", "And he opened his mouth in blasphemy against God,"], ["ua ia upu leaga i lona suafa,", "to blaspheme his name,"], ["ma lona fale fetafai,", "and his tabernacle,"], ["atoa ma e ua nonofo i le lagi.", "and them that dwell in heaven."]]},
  {num:7,words:[["Ua tuuina atu foi ia te ia ia tau le taua ma le au paia,", "And it was given unto him to make war with the saints,"], ["ma ia manumalo ia te i latou;", "and to overcome them:"], ["ua tuuina atu foi ia te ia e pule i itu aiga uma,", "and power was given him over all kindreds,"], ["ma gagana eseese,", "and tongues,"], ["ma nuu.", "and nations."]]},
  {num:8,words:[["Ua ifo foi ia te ia o i latou uma o e nonofo i le lalolagi,", "And all that dwell upon the earth shall worship him,"], ["ē ua le tusia o latou igoa i le tusi o le ola a le Tamai mamoe na fasia talu ona faavaeina o le lalolagi.", "whose names are not written in the book of life of the Lamb slain from the foundation of the world."]]},
  {num:9,words:[["Ai se tasi ua i ai taliga,", "If any man have an ear,"], ["ina faalogo mai ia o ia.", "let him hear."]]},
  {num:10,words:[["Ai se na te ta'ita'iina nisi faatagataotaua, e alu lava ia faatagataotaua;", "He that leadeth into captivity shall go into captivity:"], ["ai se na te fasiotia i le pelu, e tusa ona fasiotia o ia i le pelu.", "he that killeth with the sword must be killed with the sword."], ["O le mea lena ua i ai le onosai ma le faatuatua o le au paia.", "Here is the patience and the faith of the saints."]]},
  {num:11,words:[["Na a'u iloa foi le tasi manu feai ua alu ae nai le fanua,", "And I beheld another beast coming up out of the earth;"], ["ua i ai foi ona nifo e lua pei o nifo o se tamai mamoe,", "and he had two horns like a lamb,"], ["a ua tautala ia pei o se tarako.", "and he spake as a dragon."]]},
  {num:12,words:[["Ua fai foi e ia le pule uma a le uluai manu feai i ona luma;", "And he exerciseth all the power of the first beast before him,"], ["ma ua faia e ia ona ia ifo o le lalolagi ma e ua nonofo ai i le uluai manu feai,", "and causeth the earth and them which dwell therein to worship the first beast,"], ["o le ua mafu lona foa na fai a mate ai;", "whose deadly wound was healed."]]},
  {num:13,words:[["ua faia foi e ia faailoga tetele,", "And he doeth great wonders,"], ["o lea ua fai ai e ia ina ia alu ifo le afi mai le lagi i le lalolagi i luma o tagata.", "so that he maketh fire come down from heaven on the earth in the sight of men,"]]},
  {num:14,words:[["Ua ia faasese foi i e ua nonofo i le lalolagi ona o ia faailoga ua tuuina atu ia te ia na te faia i luma o le manu feai,", "And deceiveth them that dwell on the earth by the means of those miracles which he had power to do in the sight of the beast; saying to them that dwell on the earth,"], ["o loo fai atu ia i e ua nonofo i le lalolagi latou te faia se faatagata o le manu feai e ona le manua i le pelu a ua ola.", "that they should make an image to the beast, which had the wound by a sword, and did live."]]},
  {num:15,words:[["Ua tuuina atu foi ia te ia na te avatua le mānava i le faatagata o le manu feai,", "And he had power to give life unto the image of the beast,"], ["ina ia tautala le faatagata o le manu feai,", "that the image of the beast should both speak,"], ["ma ia faia ina ia fasiotia i latou uma o e le ifo atu i le faatagata o le manu feai.", "and cause that as many as would not worship the image of the beast should be killed."]]},
  {num:16,words:[["Ua faia foi e ia ona ia faailogaina o tagata uma,", "And he causeth all,"], ["o tagata nuu atoa ma alii,", "both small and great,"], ["o e mauoa ma e matitiva,", "rich and poor,"], ["o e sa'oloto ma e pologa,", "free and bond,"], ["ia faailogaina i latou i o latou lima taumatau,", "to receive a mark in their right hand,"], ["po o latou muaulu;", "or in their foreheads:"]]},
  {num:17,words:[["ina ia le mafaia ona faatau mai pe faatau atu e se tasi,", "And that no man might buy or sell,"], ["tau lava o e ua i ai le faailoga,", "save he that had the mark,"], ["po o le igoa o le manu feai,", "or the name of the beast,"], ["po o le faitau aofai o lona igoa.", "or the number of his name."]]},
  {num:18,words:[["O le mea lenei ua i ai le poto.", "Here is wisdom."], ["O le ua i ai le mafaufau ina faitau ia o ia i le faitau aofai o le manu feai;", "Let him that hath understanding count the number of the beast:"], ["auā o le faitau aofai lea o le tagata; o lona faitau aofai foi,", "for it is the number of a man;"], ["E ono selau ma le onogafulu ma le ono.", "and his number is Six hundred threescore and six."]]},
];
renderVerseSet(rev_ch_13_Verses, 'rev-ch13-verses');

var rev_ch_14_Verses = [
  {num:1,words:[["Na a'u iloa,", "And I looked,"], ["faauta foi,", "and,"], ["ua tu mai le Tamai mamoe i le mauga o Siona,", "lo, a Lamb stood on the mount Sion,"], ["ua faatasi foi ma ia tagata e selau afe ma afe e fa sefulu ma le fa o afe,", "and with him an hundred forty and four thousand,"], ["ua tusia le suafa o lona Tamā i o latou muaulu.", "having his Father's name written in their foreheads."]]},
  {num:2,words:[["Ua ou faalogo foi i le leo mai le lagi e pei o le taalili o vai e tele,", "And I heard a voice from heaven,"], ["e pei o le taalili foi o le faititili tetele;", "as the voice of many waters, and as the voice of a great thunder:"], ["ua ou faalogo foi i le leo o e ta kitara o loo ta i a latou kitara.", "and I heard the voice of harpers harping with their harps:"]]},
  {num:3,words:[["Ua latou pepese foi e peiseai o se pese fou i luma o le nofoālii,", "And they sung as it were a new song before the throne,"], ["ma luma o mea ola e fa,", "and before the four beasts,"], ["ma le au toeaina;", "and the elders:"], ["e le mafaia foi e se tasi ona a'oa'o i lea pese,", "and no man could learn that song but the hundred and forty and four thousand,"], ["na o le selau afe ma afe e fa sefulu ma le fa o afe o e ua faatauina nai le lalolagi.", "which were redeemed from the earth."]]},
  {num:4,words:[["O tagata ia e lei leaga i fafine; auā o taupou i latou;", "These are they which were not defiled with women;"], ["o i latou ia o e ua mulimuli atu i le Tamai mamoe i mea uma e alu i ai o ia;", "for they are virgins. These are they which follow the Lamb whithersoever he goeth. These were redeemed from among men,"], ["o i latou ia o e ua faatauina nai tagata, o e ua faapolopoloina mo le Atua ma le Tamai mamoe;", "being the firstfruits unto God and to the Lamb."]]},
  {num:5,words:[["e le iloa foi se pepelo i o latou gutu;", "And in their mouth was found no guile:"], ["auā e le ponā i latou i luma o le nofoālii o le Atua.", "for they are without fault before the throne of God."]]},
  {num:6,words:[["Na a'u iloa foi le tasi agelu ua lele i le taulotoaiga o le lagi,", "And I saw another angel fly in the midst of heaven,"], ["ua ia te ia le tala lelei e faavavau e folafola atu i e nonofo i le lalolagi i atu nuu uma,", "having the everlasting gospel to preach unto them that dwell on the earth,"], ["ma itu aiga,", "and to every nation, and kindred,"], ["ma gagana eseese,", "and tongue,"], ["ma nuu,", "and people,"]]},
  {num:7,words:[["ua faapea atu ma le leo tele,", "Saying with a loud voice,"], ["Ia outou matatau i le Atua,", "Fear God,"], ["ma avatu ia te ia le viiga,", "and give glory to him;"], ["auā ua oo mai le itu aso o lana faamasinoga;", "for the hour of his judgment is come:"], ["ma ia outou ifo i le na faia le lagi,", "and worship him that made heaven,"], ["ma le fanua,", "and earth,"], ["ma le sami,", "and the sea,"], ["atoa ma puna o vai.", "and the fountains of waters."]]},
  {num:8,words:[["Ona mulimuli atu ai lea o le tasi agelu,", "And there followed another angel,"], ["ua faapea atu,", "saying,"], ["Ua paū,", "Babylon is fallen, is fallen,"], ["ua paū Papelonia o le aai tele,", "that great city,"], ["auā ua ia faainu i nuu uma i le uaina o le toasa i lana faitaaga.", "because she made all nations drink of the wine of the wrath of her fornication."]]},
  {num:9,words:[["Ona mulimuli atu ai lea ia te i laua o lona toatolu o agelu,", "And the third angel followed them,"], ["ua faapea atu ma le leo tele,", "saying with a loud voice,"], ["Ai se tasi e ifo i le manu feai ma lona faatagata,", "If any man worship the beast and his image, and receive his mark in his forehead,"], ["ma talia le faailoga i lona muaulu po o lona lima,", "or in his hand,"]]},
  {num:10,words:[["e inu lava ia i le uaina o le toasa o le Atua,", "The same shall drink of the wine of the wrath of God,"], ["ua liligiina atu e le suia i le ipu o lona toasa,", "which is poured out without mixture into the cup of his indignation; and he shall be tormented with fire and brimstone in the presence of the holy angels,"], ["e puapuagatia foi ai i le afi ma le teio i luma o le au agelu paia ma luma o le Tamai mamoe;", "and in the presence of the Lamb:"]]},
  {num:11,words:[["o le asu foi o lo latou puapuaga e alu ae e faavavau faavavau lava;", "And the smoke of their torment ascendeth up for ever and ever:"], ["latou te le maua foi se filemu i le ao ma le po o e ua ifo i le manu feai ma lona faatagata,", "and they have no rest day nor night, who worship the beast and his image,"], ["ma se na te talia le faailoga o lona igoa.", "and whosoever receiveth the mark of his name."]]},
  {num:12,words:[["O le mea lenei ua i ai le onosai o le au paia;", "Here is the patience of the saints: here are they that keep the commandments of God,"], ["o le mea lenei ua i ai e ua tausi i poloaiga a le Atua ma le faatuatua ia Iesu.", "and the faith of Jesus."]]},
  {num:13,words:[["Na ou faalogo foi i le leo mai le lagi,", "And I heard a voice from heaven saying unto me,"], ["ua faapea mai ia te au,", "Write,"], ["Ia e tusi,", "Blessed are the dead which die in the Lord from henceforth:"], ["Amuia ē ua oti, o e ua oti o i le Alii e amata i nei ona po. O lea lava,", "Yea,"], ["ua fetalai mai ai le Agaga,", "saith the Spirit,"], ["ina ua latou malolo i a latou galuega tiga;", "that they may rest from their labours;"], ["o a latou galuega foi e mulimuli ia te i latou.", "and their works do follow them."]]},
  {num:14,words:[["Na a'u iloa faauta foi,", "And I looked,"], ["o le ao sinasina,", "and behold a white cloud,"], ["ua tietie foi i le ao le tasi ua pei o le Atalii o le tagata,", "and upon the cloud one sat like unto the Son of man,"], ["ua i lona ao le palealii auro,", "having on his head a golden crown,"], ["ua i lona aao foi le selesaito maai.", "and in his hand a sharp sickle."]]},
  {num:15,words:[["Ua alu atu foi le tasi agelu nai le malumalu,", "And another angel came out of the temple,"], ["ua alaga ma le leo tele i le ua tietie i le ao,", "crying with a loud voice to him that sat on the cloud,"], ["Ina faaoo atu ia lau selesaito,", "Thrust in thy sickle,"], ["ina sele,", "and reap:"], ["auā ua oo i ona po e te selesele ai,", "for the time is come for thee to reap;"], ["auā ua afu le saito o le lalolagi.", "for the harvest of the earth is ripe."]]},
  {num:16,words:[["Ona faaoo mai lea e le ua tietie i le ao lana selesaito i le lalolagi,", "And he that sat on the cloud thrust in his sickle on the earth;"], ["ua seleseleina ai le lalolagi.", "and the earth was reaped."]]},
  {num:17,words:[["Ua alu atu foi le tasi agelu nai le malumalu o i le lagi,", "And another angel came out of the temple which is in heaven,"], ["ua ia te ia foi le selesaito maai.", "he also having a sharp sickle."]]},
  {num:18,words:[["O le tasi agelu foi ua alu atu nai le fata faitaulaga,", "And another angel came out from the altar,"], ["ua ia te ia le pule i le afi,", "which had power over fire;"], ["ua alaga foi ia ma le leo tele i le ua i ai le selesaito maai,", "and cried with a loud cry to him that had the sharp sickle,"], ["ua faapea atu,", "saying,"], ["Ina faaoo atu ia lau selesaito maai,", "Thrust in thy sharp sickle,"], ["ina sala ia i fuifui vine o le vine o le lalolagi,", "and gather the clusters of the vine of the earth;"], ["auā ua otatā ona fuifui vine.", "for her grapes are fully ripe."]]},
  {num:19,words:[["Ona faaoo mai ai lea e le agelu o lana selesaito i le lalolagi,", "And the angel thrust in his sickle into the earth,"], ["ua sala foi e ia le vine o le lalolagi,", "and gathered the vine of the earth,"], ["ua ia lafo atu foi i totonu o le soligāvine tele o le toasa o le Atua.", "and cast it into the great winepress of the wrath of God."]]},
  {num:20,words:[["Ua solia foi le soligāvine i tua o le aai,", "And the winepress was trodden without the city,"], ["ua alu atu foi le toto nai le soligāvine e oo i faagutu o solofanua,", "and blood came out of the winepress, even unto the horse bridles,"], ["e tasi le afe ma le ono o selau o setatio ua pau mai ai.", "by the space of a thousand and six hundred furlongs."]]},
];
renderVerseSet(rev_ch_14_Verses, 'rev-ch14-verses');

var rev_ch_15_Verses = [
  {num:1,words:[["Na ou iloa foi i le lagi le tasi faailoga tele e ofo ai,", "And I saw another sign in heaven,"], ["o agelu e toafitu ua i ai mala e fitu e gata ai;", "great and marvellous, seven angels having the seven last plagues;"], ["auā e faaiuina ai le toasa o le Atua.", "for in them is filled up the wrath of God."]]},
  {num:2,words:[["Na ou iloa atu foi ua peiseai o se sami tioata ua fefiloi ma le afi;", "And I saw as it were a sea of glass mingled with fire:"], ["o i latou foi na manumalo i le manu feai,", "and them that had gotten the victory over the beast,"], ["ma lona faatagata,", "and over his image,"], ["ma lona faailoga,", "and over his mark,"], ["ma le faitau aofai o lona igoa,", "and over the number of his name,"], ["ua tutū i latou i le sami tioata,", "stand on the sea of glass,"], ["ua ia te i latou kitara a le Atua.", "having the harps of God."]]},
  {num:3,words:[["Ua latou pepese i le pese a Mose le auauna a le Atua,", "And they sing the song of Moses the servant of God,"], ["ma le pese a le Tamai mamoe,", "and the song of the Lamb,"], ["ua faapea atu,", "saying,"], ["Le Alii e, le Atua e ou le malosi uma lava,", "Great and marvellous are thy works,"], ["ua tetele au galuega e ofo ai;", "Lord God Almighty;"], ["e tonu ma faamaoni ou ala,", "just and true are thy ways,"], ["le Tupu o le au paia e.", "thou King of saints."]]},
  {num:4,words:[["Le Alii e,", "Who shall not fear thee,"], ["o ai se le mata'u ia te oe,", "O Lord,"], ["ma vivii atu i lou suafa? auā ua na o oe e lelei; auā e o mai nuu uma lava,", "and glorify thy name? for thou only art holy:"], ["ma latou ifo i ou luma;", "for all nations shall come and worship before thee;"], ["auā ua faaalia au faamasinoga tonu.", "for thy judgments are made manifest."]]},
  {num:5,words:[["Ua mavae nei mea,", "And after that I looked,"], ["ona ou vaai lea,", "and,"], ["faauta foi,", "behold,"], ["ua faaavanoaina i le lagi le malumalu o i le fale fetafai o i ai le mau;", "the temple of the tabernacle of the testimony in heaven was opened:"]]},
  {num:6,words:[["ona o atu lea nai le malumalu o agelu e toafitu ua i ai mala e fitu,", "And the seven angels came out of the temple,"], ["ua oofu i latou i ie lino e mamā ma le pupula,", "having the seven plagues, clothed in pure and white linen,"], ["ua fusia foi o latou fatafata i fusi auro.", "and having their breasts girded with golden girdles."]]},
  {num:7,words:[["O le tasi foi o mea ola e fa ua ia avatu i agelu e toafitu o ipu auro e fitu,", "And one of the four beasts gave unto the seven angels seven golden vials full of the wrath of God,"], ["ua tutumu i le toasa o le Atua o lē soifua e faavavau faavavau lava.", "who liveth for ever and ever."]]},
  {num:8,words:[["Ua tumu foi le malumalu i le asu nai le pupula o le Atua atoa ma lona mana;", "And the temple was filled with smoke from the glory of God,"], ["e le mafaia foi e se tasi ona ulu atu i le malumalu,", "and from his power; and no man was able to enter into the temple,"], ["seia faaiuina mala e fitu a agelu e toafitu.", "till the seven plagues of the seven angels were fulfilled."]]},
];
renderVerseSet(rev_ch_15_Verses, 'rev-ch15-verses');

var rev_ch_16_Verses = [
  {num:1,words:[["Na ou lagona foi le leo tele mai le malumalu,", "And I heard a great voice out of the temple saying to the seven angels,"], ["ua faapea atu i agelu e toafitu, O ia,", "Go your ways,"], ["ina liligi atu ipu o le toasa o le Atua i le lalolagi.", "and pour out the vials of the wrath of God upon the earth."]]},
  {num:2,words:[["Ona alu atu ai lea o lē muamua,", "And the first went,"], ["ua liligi ifo lana ipu i le fanua;", "and poured out his vial upon the earth;"], ["ona oo lea o le papala leaga e tiga ai tagata ua i ai le faailoga o le manu feai,", "and there fell a noisome and grievous sore upon the men which had the mark of the beast,"], ["atoa ma ē ua ifo i lona faatagata.", "and upon them which worshipped his image."]]},
  {num:3,words:[["Ua liligi foi e lona toalua o agelu lana ipu i le sami;", "And the second angel poured out his vial upon the sea;"], ["ona liu toto ai lea e pei o le toto o le tagata oti;", "and it became as the blood of a dead man:"], ["ona mamate ai lea o mea ola uma o i le sami.", "and every living soul died in the sea."]]},
  {num:4,words:[["Ua liligi foi e lona toatolu o agelu lana ipu i vaitafe ma puna o vai;", "And the third angel poured out his vial upon the rivers and fountains of waters;"], ["ona liu toto ai lea.", "and they became blood."]]},
  {num:5,words:[["Na ou lagona foi le agelu e pule i vai ua faapea atu,", "And I heard the angel of the waters say,"], ["Le Alii e,", "Thou art righteous,"], ["o lē amiotonu oe,", "O Lord,"], ["o lē soifua,", "which art,"], ["o le na soifua,", "and wast,"], ["ma loo lelei,", "and shalt be,"], ["auā ua faapea ona e faasalaina.", "because thou hast judged thus."]]},
  {num:6,words:[["Auā na latou faamaligiina le toto o tagata paia ma perofeta,", "For they have shed the blood of saints and prophets,"], ["i le ua e avatu ai ia te i latou le toto e inu ai;", "and thou hast given them blood to drink;"], ["auā ua tatau lea mo i latou.", "for they are worthy."]]},
  {num:7,words:[["Na ou lagona foi i le tasi mai le fata faitaulaga, ua faapea atu,", "And I heard another out of the altar say,"], ["E moni,", "Even so,"], ["le Alii e,", "Lord God Almighty,"], ["le Atua e ou le malosi uma lava; e faamaoni ma le tonu au faamasinoga.", "true and righteous are thy judgments."]]},
  {num:8,words:[["Ua liligi foi e lona toafa o agelu lana ipu i le la;", "And the fourth angel poured out his vial upon the sun;"], ["ua tuuina atu i ai ia mu ai tagata i le afi;", "and power was given unto him to scorch men with fire."]]},
  {num:9,words:[["ua mu foi tagata i le mu tele,", "And men were scorched with great heat,"], ["ona latou faifai lea i le suafa o le Atua e ana le pule i ia mala;", "and blasphemed the name of God, which hath power over these plagues:"], ["a ua le salamo i latou e avatu ai le viiga ia te ia.", "and they repented not to give him glory."]]},
  {num:10,words:[["Ua liligi foi e lona toalima o agelu lana ipu i le nofoālii o le manu feai;", "And the fifth angel poured out his vial upon the seat of the beast;"], ["ona faapouliuligia lea o lona malo;", "and his kingdom was full of darkness;"], ["ona latou feati ai lea o latou laulaufaiva ona o le puapuaga;", "and they gnawed their tongues for pain,"]]},
  {num:11,words:[["ua latou faifai foi i le Atua o le lagi ona o latou puapuaga atoa ma o latou papala,", "And blasphemed the God of heaven because of their pains and their sores,"], ["ua le salamo foi i latou i a latou amio.", "and repented not of their deeds."]]},
  {num:12,words:[["Ua liligi foi e lona toaono o agelu lana ipu i le vaitafe tele o Eufirate;", "And the sixth angel poured out his vial upon the great river Euphrates;"], ["ona mate ai lea o lona vai,", "and the water thereof was dried up,"], ["ina ia saunia le ala o tupu mai nuu e alu ae ai le la.", "that the way of the kings of the east might be prepared."]]},
  {num:13,words:[["Ona ou iloa ai lea o agaga leaga e toatolu e pei o rane ua o mai mai le gutu o le tarako,", "And I saw three unclean spirits like frogs come out of the mouth of the dragon,"], ["ma le gutu o le manu feai,", "and out of the mouth of the beast,"], ["atoa ma le gutu o le perofeta pepelo;", "and out of the mouth of the false prophet."]]},
  {num:14,words:[["auā o agaga ia o temoni e fai faailoga,", "For they are the spirits of devils,"], ["ua latou o atu i tupu o le lalolagi ma le atu laulau uma,", "working miracles, which go forth unto the kings of the earth and of the whole world,"], ["e faapotopoto ia te i latou i le taua i le aso tele o le Atua e ona le malosi uma lava.", "to gather them to the battle of that great day of God Almighty."]]},
  {num:15,words:[["(Faauta,", "Behold,"], ["ou te alu atu pei o se gaoi;", "I come as a thief. Blessed is he that watcheth,"], ["amuia lē mataala, ma tausi i ona ofu,", "and keepeth his garments,"], ["ina ne'i savali o ia e lē lavalavā,", "lest he walk naked,"], ["ne'i latou iloa atu foi lona mā.)", "and they see his shame."]]},
  {num:16,words:[["Na ia faapotopoto foi ia te i latou i le mea ua igoa i le upu Eperu o Amaketo.", "And he gathered them together into a place called in the Hebrew tongue Armageddon."]]},
  {num:17,words:[["Ua liligi foi e lona toafitu o agelu lana ipu i le matagi;", "And the seventh angel poured out his vial into the air;"], ["ona tŭlei mai ai lea o le siufofoga tele mai le malumalu o i le lagi mai le nofoālii,", "and there came a great voice out of the temple of heaven,"], ["ua faapea mai,", "from the throne, saying,"], ["Ua uma ona fai.", "It is done."]]},
  {num:18,words:[["Ona tutupu ai lea o leo,", "And there were voices,"], ["ma faititili,", "and thunders, and lightnings;"], ["ma uila,", "and there was a great earthquake,"], ["sa i ai foi le mafuie tele,", "such as was not since men were upon the earth, so mighty an earthquake,"], ["e le faapea ona tele se mafuie ua tele naua talu ona i ai o tagata i le lalolagi.", "and so great."]]},
  {num:19,words:[["Ua vaetoluina foi le aai tele,", "And the great city was divided into three parts,"], ["ua pauu foi aai o nuu;", "and the cities of the nations fell:"], ["ua manatua Papelonia le aai tele i luma o le Atua,", "and great Babylon came in remembrance before God,"], ["ina ia tuuina atu ia te ia o le ipu o le uaina o lona toasa mamafa.", "to give unto her the cup of the wine of the fierceness of his wrath."]]},
  {num:20,words:[["Ua sosola foi motu uma,", "And every island fled away,"], ["o mauga foi ua le iloa.", "and the mountains were not found."]]},
  {num:21,words:[["Ua to mai foi ai le lagi i luga o tagata le uato'a latetele,", "And there fell upon men a great hail out of heaven,"], ["e pei o le taleni ona mamafa;", "every stone about the weight of a talent:"], ["ona faifai ai lea o tagata i le Atua ona o le mala o le uato'a,", "and men blasphemed God because of the plague of the hail;"], ["auā ua matuā tele lea mala.", "for the plague thereof was exceeding great."]]},
];
renderVerseSet(rev_ch_16_Verses, 'rev-ch16-verses');

var rev_ch_17_Verses = [
  {num:1,words:[["Ua sau foi le tasi o ia agelu e toafitu sa i ai ipu e fitu,", "And there came one of the seven angels which had the seven vials,"], ["ua tautala mai ia te au,", "and talked with me,"], ["ua faapea mai ia te au, Sau ia,", "saying unto me,"], ["ou te faailoa ia te oe le faasalaina o le fafine talitane e sili,", "Come hither;"], ["o lē tietie i vai e tele;", "I will shew unto thee the judgment of the great whore that sitteth upon many waters:"]]},
  {num:2,words:[["ua faitaaga ma ia o tupu o le lalolagi,", "With whom the kings of the earth have committed fornication,"], ["ua onā foi e o nonofo i le lalolagi i le uaina o lana faitaaga.", "and the inhabitants of the earth have been made drunk with the wine of her fornication."]]},
  {num:3,words:[["Ua ia avea foi a'u i le vao i le Agaga;", "So he carried me away in the spirit into the wilderness:"], ["ona ou iloa lea o le fafine ua tietie i le manu feai mūmū,", "and I saw a woman sit upon a scarlet coloured beast,"], ["ua lilo i igoa faifai,", "full of names of blasphemy,"], ["e fitu ona ulu ma ona nifo e sefulu.", "having seven heads and ten horns."]]},
  {num:4,words:[["Ua ofu le fafine i le ie pāuli ma le mūmū, ua teuteu foi i auro,", "And the woman was arrayed in purple and scarlet colour,"], ["ma maa tāua, ma penina,", "and decked with gold and precious stones and pearls,"], ["ua i lona lima le ipu auro, ua tumu i mea e inosia ma le leaga o lana faitaaga;", "having a golden cup in her hand full of abominations and filthiness of her fornication:"]]},
  {num:5,words:[["ua tusia foi i lona muaulu le igoa,", "And upon her forehead was a name written,"], ["O Le mea lilo,", "MYSTERY,"], ["Papelonia le aai tele,", "BABYLON THE GREAT,"], ["o le tina o fafine talitane ma mea e inosia i le lalolagi .", "THE MOTHER OF HARLOTS AND ABOMINATIONS OF THE EARTH."]]},
  {num:6,words:[["Na ou iloa foi le fafine ua onā i le toto o le au paia ma le toto o e na molimau ia Iesu;", "And I saw the woman drunken with the blood of the saints,"], ["ua ou iloa atu ia te ia,", "and with the blood of the martyrs of Jesus: and when I saw her,"], ["ona ou matuā ofo tele ai lea.", "I wondered with great admiration."]]},
  {num:7,words:[["Ona fai mai lea o le agelu ia te au,", "And the angel said unto me,"], ["Se a le mea ua e ofo ai? Ou te ta'u atu ia te oe le uiga lilo o le fafine,", "Wherefore didst thou marvel? I will tell thee the mystery of the woman,"], ["ma le manu feai ua ia tietie ai,", "and of the beast that carrieth her,"], ["e fitu ona ulu ma ona nifo e sefulu.", "which hath the seven heads and ten horns."]]},
  {num:8,words:[["O le manu feai na e iloa,", "The beast that thou sawest was,"], ["sa i ai,", "and is not;"], ["ua le i ai foi, o le a alu ae foi o ia ai le to e le gata,", "and shall ascend out of the bottomless pit,"], ["e alu atu foi o ia i le malaia;", "and go into perdition:"], ["o e nonofo i le lalolagi,", "and they that dwell on the earth shall wonder,"], ["(e lei tusia o latou igoa i le tusi o le ola talu ona faavaeina o le lalolagi,", "whose names were not written in the book of life from the foundation of the world,"], [") latou te taufaiofo, pe a iloa le manu feai sa i ai,", "when they behold the beast that was,"], ["ua le i ai foi,", "and is not,"], ["a e ui i lea o loo i ai lava.", "and yet is."]]},
  {num:9,words:[["O le mea lenei ua i ai le atamai e ona le poto. O ulu e fitu o mauga ia e fitu,", "And here is the mind which hath wisdom. The seven heads are seven mountains,"], ["ua nofo ai le fafine;", "on which the woman sitteth."]]},
  {num:10,words:[["o tupu foi ia e toafitu;", "And there are seven kings:"], ["e toalima ua pauu,", "five are fallen,"], ["o loo i ai le tasi,", "and one is, and the other is not yet come;"], ["e lei oo mai nei foi le tasi;", "and when he cometh,"], ["pe a oo mai e tusa ona saasaa ona po e tumau ai.", "he must continue a short space."]]},
  {num:11,words:[["O le manu feai foi sa i ai,", "And the beast that was,"], ["ua le i ai foi,", "and is not,"], ["o lona toavalu lea,", "even he is the eighth,"], ["nai le toafitu foi o ia,", "and is of the seven,"], ["e alu atu foi o ia i le malaia.", "and goeth into perdition."]]},
  {num:12,words:[["O nifo foi e sefulu na e iloa,", "And the ten horns which thou sawest are ten kings,"], ["o tupu ia e toasefulu, ua le oo ina maua o latou malo,", "which have received no kingdom as yet;"], ["a e maua e i latou le pule pei o tupu e tasi le itu aso faatasi ma le manu feai.", "but receive power as kings one hour with the beast."]]},
  {num:13,words:[["Ua loto gatasi i latou nei,", "These have one mind,"], ["latou te avatu foi o latou malosi ma a latou pule i le manu feai.", "and shall give their power and strength unto the beast."]]},
  {num:14,words:[["Latou te tau le taua ma le Tamai mamoe,", "These shall make war with the Lamb,"], ["a e manumalo le Tamai mamoe ia te i latou,", "and the Lamb shall overcome them:"], ["auā o le Alii ia o alii ma le Tupu o tupu;", "for he is Lord of lords, and King of kings:"], ["o e ua ia te ia foi ua valaauina i latou,", "and they that are with him are called,"], ["ma filifilia,", "and chosen,"], ["ma faamaoni.", "and faithful."]]},
  {num:15,words:[["Ona fai mai lea o ia ia te au,", "And he saith unto me,"], ["O vai na e iloa,", "The waters which thou sawest,"], ["o loo tietie ai le fafine talitane,", "where the whore sitteth,"], ["o nuu ia,", "are peoples,"], ["ma motu o tagata,", "and multitudes,"], ["ma atu nuu,", "and nations,"], ["ma gagana eseese.", "and tongues."]]},
  {num:16,words:[["O nifo foi e sefulu na e iloa i le manu feai,", "And the ten horns which thou sawest upon the beast,"], ["latou te 'ino'ino i le fafine talitane,", "these shall hate the whore,"], ["ma faasaunoa ia te ia, ma to ese ona ofu,", "and shall make her desolate and naked,"], ["latou te aai foi i lona tino,", "and shall eat her flesh,"], ["ma susunu ia te ia i le afi.", "and burn her with fire."]]},
  {num:17,words:[["Auā ua tuuina atu e le Atua i o latou loto ia faia lona finagalo,", "For God hath put in their hearts to fulfil his will,"], ["latou te loto gatasi foi e avatu lo latou malo mo le manu feai,", "and to agree, and give their kingdom unto the beast,"], ["seia taunuu afioga a le Atua.", "until the words of God shall be fulfilled."]]},
  {num:18,words:[["O le fafine foi na e iloa, o le aai tele lea,", "And the woman which thou sawest is that great city,"], ["e i ai le pule i tupu o le lalolagi.", "which reigneth over the kings of the earth."]]},
];
renderVerseSet(rev_ch_17_Verses, 'rev-ch17-verses');

var rev_ch_18_Verses = [
  {num:1,words:[["Ua mavae ia mea,", "And after these things I saw another angel come down from heaven,"], ["ona ou iloa atu lea o le agelu o loo alu ifo i le lagi, ua ia te ia le pule sili;", "having great power;"], ["ua malamalama foi le lalolagi i lona pupula.", "and the earth was lightened with his glory."]]},
  {num:2,words:[["Ua matuā alaga foi o ia ma le leo tele,", "And he cried mightily with a strong voice,"], ["ua faapea ane,", "saying,"], ["Ua paū,", "Babylon the great is fallen,"], ["ua paū Papelonia le aai tele,", "is fallen,"], ["ua avea foi o ia ma mea e nofo ai temoni,", "and is become the habitation of devils,"], ["ma mea e puipui ai agaga leaga uma,", "and the hold of every foul spirit,"], ["o le mea foi e puipui ai manu felelei uma e leaga ma le inosia;", "and a cage of every unclean and hateful bird."]]},
  {num:3,words:[["auā ua feinu nuu uma i le uaina o le toasa i lana faitaaga,", "For all nations have drunk of the wine of the wrath of her fornication,"], ["ua faitaaga foi ma ia tupu o le lalolagi,", "and the kings of the earth have committed fornication with her,"], ["o le faulaiga o ana mea faafiafia ua tamaoaiga ai e ua faatau oa o i le lalolagi.", "and the merchants of the earth are waxed rich through the abundance of her delicacies."]]},
  {num:4,words:[["Ua ou faalogo foi i le tasi leo mai le lagi,", "And I heard another voice from heaven,"], ["ua faapea mai,", "saying,"], ["Lo'u nuu e,", "Come out of her,"], ["ia outou o ese ia te ia,", "my people,"], ["ina ne'i faatasia outou i ana agasala,", "that ye be not partakers of her sins,"], ["ina ne'i tofusia foi outou i ona mala;", "and that ye receive not of her plagues."]]},
  {num:5,words:[["auā ua pa'i atu ana agasala i le lagi,", "For her sins have reached unto heaven,"], ["ua manatua foi e le Atua ana amioleaga.", "and God hath remembered her iniquities."]]},
  {num:6,words:[["Ia outou taui atu ia te ia ia pei ona taui mai e ia ia te outou,", "Reward her even as she rewarded you,"], ["ia outou taui faalua ia te ia e tusa ma ana galuega; o le ipu foi na liligi mai ai e ia,", "and double unto her double according to her works:"], ["ia outou liligi faaluaina atu ai ia te ia.", "in the cup which she hath filled fill to her double."]]},
  {num:7,words:[["E pei ona mitamita o ia ia te ia,", "How much she hath glorified herself,"], ["mona ua faafiafia o ia ia te ia,", "and lived deliciously,"], ["ia faapea ona outou tuuina atu ia te ia o le puapuaga ma le faanoanoa. Auā ua faapea ifo ia i lona loto,", "so much torment and sorrow give her: for she saith in her heart,"], ["Ou te nofo nei o le tupu fafine,", "I sit a queen,"], ["ou te le se fafine ua oti lana tane,", "and am no widow,"], ["ou te le iloa lava se faanoanoa;", "and shall see no sorrow."]]},
  {num:8,words:[["o le mea lea e oo mai ai i le aso e tasi ona mala,", "Therefore shall her plagues come in one day,"], ["o le oti,", "death,"], ["ma le faanoanoa,", "and mourning,"], ["ma le oge;", "and famine;"], ["e susunuina foi o ia i le afi;", "and she shall be utterly burned with fire:"], ["auā e malosi lava le Alii le Atua o lē faasala ia te ia.", "for strong is the Lord God who judgeth her."]]},
  {num:9,words:[["O tupu foi o le lalolagi e na faitaaga ma faafiafia i latou faatasi ma ia,", "And the kings of the earth, who have committed fornication and lived deliciously with her,"], ["latou te taufaitagi ia te ia ma taufaitagitu'i ona o ia,", "shall bewail her,"], ["pe a latou iloa atu le asu o lona susunuina;", "and lament for her, when they shall see the smoke of her burning,"]]},
  {num:10,words:[["e tutū mamao i latou ona o le fefe i lona puapuaga,", "Standing afar off for the fear of her torment,"], ["e faapea atu,", "saying,"], ["Aue,", "Alas, alas,"], ["aue Papelonia e,", "that great city Babylon,"], ["le aai tele ma le aai malosi! auā o le itu aso e tasi ua oo mai ai lau sala.", "that mighty city! for in one hour is thy judgment come."]]},
  {num:11,words:[["O faatauoa foi i le lalolagi e taufaitagi i latou ma faanoanoa ona o ia;", "And the merchants of the earth shall weep and mourn over her;"], ["auā e le toe faatau e se tasi a latou oloa;", "for no man buyeth their merchandise any more:"]]},
  {num:12,words:[["o le oloa auro,", "The merchandise of gold,"], ["ma ario,", "and silver,"], ["ma maa tāua,", "and precious stones,"], ["ma penina,", "and of pearls,"], ["ma ie vavae,", "and fine linen,"], ["ma ie pāuli,", "and purple,"], ["ma le silika,", "and silk,"], ["ma le ie mūmū,", "and scarlet,"], ["ma laau tuina uma,", "and all thyine wood,"], ["ma ipu nifo elefane uma,", "and all manner vessels of ivory,"], ["ma ipu laau matuā tāua uma,", "and all manner vessels of most precious wood,"], ["ma le 'apa memea,", "and of brass,"], ["ma le uamea,", "and iron,"], ["ma le maremaru,", "and marble,"]]},
  {num:13,words:[["ma kinamomi,", "And cinnamon,"], ["ma mea manogi,", "and odours,"], ["ma le suāuu manogi,", "and ointments,"], ["ma le pulu lipano,", "and frankincense,"], ["ma le uaina,", "and wine,"], ["ma le uu olive,", "and oil,"], ["ma le falaoa lelei,", "and fine flour, and wheat,"], ["ma le saito,", "and beasts,"], ["ma manu,", "and sheep,"], ["ma mamoe,", "and horses,"], ["ma solofanua,", "and chariots,"], ["ma nofoa faataavalevale,", "and slaves,"], ["o tino foi atoa ma agaga o tagata.", "and souls of men."]]},
  {num:14,words:[["Ua te'a foi ma oe o fua na e tu'inanau i ai,", "And the fruits that thy soul lusted after are departed from thee,"], ["ua te'a foi ma oe mea lalelei uma ma mea pupula,", "and all things which were dainty and goodly are departed from thee,"], ["e te le toe maua lava ia mea.", "and thou shalt find them no more at all."]]},
  {num:15,words:[["O e faatau ia mea,", "The merchants of these things,"], ["o e tamaoaiga ona o ia,", "which were made rich by her,"], ["latou te tutū mamao ma le fefe i lona puapuaga,", "shall stand afar off for the fear of her torment,"], ["o loo taufaitagi ma faanoanoa,", "weeping and wailing,"]]},
  {num:16,words:[["o loo faapea atu,", "And saying,"], ["Aue,", "Alas, alas,"], ["aue le aai tele,", "that great city,"], ["na ofu i le ie vavae ma le pāuli,", "that was clothed in fine linen, and purple,"], ["ma le mūmū,", "and scarlet,"], ["na teteu foi i auro,", "and decked with gold, and precious stones,"], ["ma maa tāua ma penina;", "and pearls!"]]},
  {num:17,words:[["auā o le itu aso e tasi ua faaumatia ai le oloa ua sili ona tele. O tautai uma,", "For in one hour so great riches is come to nought. And every shipmaster,"], ["atoa ma tagata uma o i vaa,", "and all the company in ships,"], ["ma auvaa,", "and sailors,"], ["atoa uma ma e feoai i le vasa,", "and as many as trade by sea,"], ["ua tutū mamao i latou,", "stood afar off,"]]},
  {num:18,words:[["ma latou alalaga ina o iloa mai le asu o lona susunuina,", "And cried when they saw the smoke of her burning,"], ["ua faapea,", "saying,"], ["O fea se aai e tusa ma lenei aai tele?", "What city is like unto this great city!"]]},
  {num:19,words:[["Ua latou lafo ae foi le eleele i o latou ulu,", "And they cast dust on their heads,"], ["ua alalaga,", "and cried,"], ["ma taufaitagi, ma faanoanoa,", "weeping and wailing,"], ["ua faapea atu,", "saying,"], ["Aue,", "Alas,"], ["aue le aai tele, na tamaoaiga ai i latou uma o e o i ai vaa i le vasa,", "alas,"], ["ona o ana mea tāua;", "that great city,"], ["auā o le itu aso e tasi ua faatafunaina ai o ia.", "wherein were made rich all that had ships in the sea by reason of her costliness! for in one hour is she made desolate."]]},
  {num:20,words:[["Ia e olioli ona o ia,", "Rejoice over her,"], ["le lagi e,", "thou heaven,"], ["atoa ma outou aposetolo paia ma perofeta;", "and ye holy apostles and prophets;"], ["auā ua faasalaina o ia e le Atua ona o le faasalaina o outou e ia.", "for God hath avenged you on her."]]},
  {num:21,words:[["Ua siitia foi e le tasi agelu malosi o le maa e pei o se maaolo tele,", "And a mighty angel took up a stone like a great millstone,"], ["ma lafo i le sami,", "and cast it into the sea,"], ["ua faapea atu,", "saying,"], ["E faapea ona lafotuina o Papelonia le aai tele,", "Thus with violence shall that great city Babylon be thrown down,"], ["e le toe iloa lava.", "and shall be found no more at all."]]},
  {num:22,words:[["E le toe lagona foi ia te oe le leo o e ta kitara,", "And the voice of harpers, and musicians,"], ["ma ē lagi siva,", "and of pipers,"], ["ma ē ili fagufagu,", "and trumpeters,"], ["atoa ma ē ili pu;", "shall be heard no more at all in thee; and no craftsman,"], ["e le toe iloa foi ia te oe se tufuga e toatasi o se faiva e tasi,", "of whatsoever craft he be, shall be found any more in thee;"], ["e le toe lagona foi ia te oe le taalili o le maaolo,", "and the sound of a millstone shall be heard no more at all in thee;"]]},
  {num:23,words:[["e le toe pupula mai foi ia te oe se malamalama o se lamepa,", "And the light of a candle shall shine no more at all in thee;"], ["e le toe lagona foi ia te oe le leo o le faatoafaiavā ma le faatoanofo tane;", "and the voice of the bridegroom and of the bride shall be heard no more at all in thee:"], ["auā o ou tagata faatauoa o tagata sili ia o i le lalolagi,", "for thy merchants were the great men of the earth;"], ["auā ua faaseseina nuu uma i au togafiti faataulāitu.", "for by thy sorceries were all nations deceived."]]},
  {num:24,words:[["Ua iloa foi ia te oe le toto o perofeta ma le au paia,", "And in her was found the blood of prophets, and of saints,"], ["ma i latou uma ua fasiotia i le lalolagi.", "and of all that were slain upon the earth."]]},
];
renderVerseSet(rev_ch_18_Verses, 'rev-ch18-verses');

var rev_ch_19_Verses = [
  {num:1,words:[["Ua mavae nei mea,", "And after these things I heard a great voice of much people in heaven,"], ["ona ou faalogo lea e peiseai o le leo tele o le motu o tagata e toatele o i le lagi,", "saying,"], ["ua faapea atu,", "Alleluia;"], ["Aleluia;", "Salvation,"], ["ua i le Alii lo tatou Atua le olataga,", "and glory,"], ["ma le viiga,", "and honour,"], ["ma le faaneeneega,", "and power,"], ["ma le mana;", "unto the Lord our God:"]]},
  {num:2,words:[["auā e faamaoni,", "For true and righteous are his judgments:"], ["e tonu foi ana faamasinoga;", "for he hath judged the great whore,"], ["auā ua faasalaina e ia le fafine talitane e sili, o le na faaleagaina le lalolagi i lana faitaaga,", "which did corrupt the earth with her fornication,"], ["ua ia taui atu ia te ia lava le toto o ana auauna.", "and hath avenged the blood of his servants at her hand."]]},
  {num:3,words:[["Ua latou toe fai atu, Aleluia;", "And again they said,"], ["ona alu ae ai lea o lona asu e faavavau faavavau lava.", "Alleluia. And her smoke rose up for ever and ever."]]},
  {num:4,words:[["Ua faapaū toeaina e toaluafulu ma le toafa, ma mea ola e fa,", "And the four and twenty elders and the four beasts fell down and worshipped God that sat on the throne,"], ["ma ua ifo i le Atua o lē tietie i le nofoālii,", "saying,"], ["ua faapea atu,", "Amen;"], ["Amene; Aleluia.", "Alleluia."]]},
  {num:5,words:[["Ua oo mai foi le leo mai le nofoālii,", "And a voice came out of the throne,"], ["ua faapea mai. Ia vivii atu i lo tatou Atua,", "saying,"], ["o outou ana auauna uma,", "Praise our God, all ye his servants,"], ["ma outou o e matatau ia te ia,", "and ye that fear him,"], ["o tagata nuu atoa ma alii.", "both small and great."]]},
  {num:6,words:[["Ua ou faalogo foi e peiseai o le leo o le motu o tagata e toatele,", "And I heard as it were the voice of a great multitude,"], ["e peiseai o le taalili o vai e tele,", "and as the voice of many waters,"], ["e peiseai o le taalili foi o faititili tetele,", "and as the voice of mighty thunderings,"], ["ua faapea atu,", "saying,"], ["Aleluia;", "Alleluia:"], ["auā ua fai ma tupu le Alii le Atua e ona le malosi uma lava.", "for the Lord God omnipotent reigneth."]]},
  {num:7,words:[["Ia tatou fiafia ma olioli,", "Let us be glad and rejoice,"], ["ma tuu atu le viiga ia te ia;", "and give honour to him:"], ["auā ua oo mai le tausamaaga o le Tamai mamoe,", "for the marriage of the Lamb is come,"], ["o lona felutua foi ua saunia o ia e ia.", "and his wife hath made herself ready."]]},
  {num:8,words:[["Ua tuuina atu foi ia te ia ina ia ofu o ia i le ie vavae e mamā ma le pupula;", "And to her was granted that she should be arrayed in fine linen, clean and white:"], ["auā o le ie vavae o le amiotonu lea a le au paia.", "for the fine linen is the righteousness of saints."]]},
  {num:9,words:[["Ua fai mai foi o ia ia te au,", "And he saith unto me,"], ["Ia e tusi,", "Write,"], ["Amuia e ua tala'iina i le tausamaaga o le Tamai mamoe. Ua fai mai foi o ia ia te au,", "Blessed are they which are called unto the marriage supper of the Lamb. And he saith unto me,"], ["O afioga moni ia a le Atua.", "These are the true sayings of God."]]},
  {num:10,words:[["Ona ou faapaū atu lea i luma o ona vae e ifo ia te ia;", "And I fell at his feet to worship him. And he said unto me,"], ["a ua fai mai o ia ia te au, Ia oe,", "See thou do it not:"], ["aua lava;", "I am thy fellowservant,"], ["o a'u o lou uso a auauna,", "and of thy brethren that have the testimony of Jesus:"], ["o so lou au uso foi ua i ai le mau ia Iesu; ia e ifo i le Atua;", "worship God:"], ["auā o le agaga o le valoaga o le mau lea ia Iesu.", "for the testimony of Jesus is the spirit of prophecy."]]},
  {num:11,words:[["Na a'u iloa atu le lagi ua avanoa,", "And I saw heaven opened,"], ["faauta foi,", "and behold a white horse;"], ["o le solofanua sinasina, o lē tietie ai foi ua igoa ia o le Faamaoni ma le Moni,", "and he that sat upon him was called Faithful and True,"], ["o le amiotonu foi na te faamasino ai ma tau ai le taua;", "and in righteousness he doth judge and make war."]]},
  {num:12,words:[["ua pei o le mumū o le afi ona fofoga,", "His eyes were as a flame of fire, and on his head were many crowns;"], ["ua i lona ao foi palealii e tele;", "and he had a name written,"], ["ua ia te ia le suafa ua tusia e le iloa e se tasi ua na o ia lava;", "that no man knew, but he himself."]]},
  {num:13,words:[["ua ofu foi o ia i le ofu ua fufui i le toto; ua faasuafaina o ia,", "And he was clothed with a vesture dipped in blood:"], ["O le Lokou o le Atua.", "and his name is called The Word of God."]]},
  {num:14,words:[["O 'au foi o i le lagi ua mulimuli atu ia te ia i luga o solofanua sisina,", "And the armies which were in heaven followed him upon white horses, clothed in fine linen,"], ["ua oofu i latou i le ie vavae sinasina ma le mamā.", "white and clean."]]},
  {num:15,words:[["Ua alu atu foi le pelu maai nai i lona fofoga,", "And out of his mouth goeth a sharp sword,"], ["ina ia taia a'i e ia o nuu;", "that with it he should smite the nations:"], ["e pule foi o ia ia te i latou i le tootoo uamea;", "and he shall rule them with a rod of iron:"], ["e soli foi e ia le soligāvine o le toasa mamafa o le Atua e ona le malosi uma lava.", "and he treadeth the winepress of the fierceness and wrath of Almighty God."]]},
  {num:16,words:[["Ua ia te ia foi le suafa ua tusia i lona ofu ma lona vae. O Le Tupu o tupu,", "And he hath on his vesture and on his thigh a name written, KING OF KINGS,"], ["ma le Alii o alii .", "AND LORD OF LORDS."]]},
  {num:17,words:[["Na a'u iloa foi le tasi agelu ua tu i le la;", "And I saw an angel standing in the sun;"], ["ua alaga foi o ia ma le leo tele,", "and he cried with a loud voice,"], ["ua faapea atu i manu uma e felelei i le taulotoaiga o le lagi, O mai ia,", "saying to all the fowls that fly in the midst of heaven,"], ["ina outou faapotopoto ane i le faigaai a le Atua silisili,", "Come and gather yourselves together unto the supper of the great God;"]]},
  {num:18,words:[["ina ia outou aai i tino o tupu,", "That ye may eat the flesh of kings,"], ["ma tino o ta'ita'i o 'au taitoaafe,", "and the flesh of captains,"], ["ma tino o tagata malolosi,", "and the flesh of mighty men,"], ["ma tino o solofanua ma e ua tietie ai,", "and the flesh of horses, and of them that sit on them,"], ["ma tino o tagata uma,", "and the flesh of all men,"], ["o e sa'oloto atoa ma pologa,", "both free and bond,"], ["o tagatānuu atoa ma alii.", "both small and great."]]},
  {num:19,words:[["Ona ou iloa lea o le manu feai,", "And I saw the beast,"], ["ma tupu o le lalolagi,", "and the kings of the earth,"], ["ma a latou 'au,", "and their armies, gathered together to make war against him that sat on the horse,"], ["ua faapotopotoina e tau ai le taua ma le ua tietie i le solofanua ma lana itu taua.", "and against his army."]]},
  {num:20,words:[["Ona puea lea o le manu feai atoa ma le perofeta pepelo o le na fai faailoga i ona luma,", "And the beast was taken,"], ["o mea ia na faaseseina ai e ia o e ua i ai le faailoga o le manu feai,", "and with him the false prophet that wrought miracles before him,"], ["ma e ua ifo i lona faatagata;", "with which he deceived them that had received the mark of the beast,"], ["ua lafoolaina i laua i le lepa afi ua mu i le teio.", "and them that worshipped his image. These both were cast alive into a lake of fire burning with brimstone."]]},
  {num:21,words:[["A o e na totoe,", "And the remnant were slain with the sword of him that sat upon the horse,"], ["ua fasiotia i latou i le pelu ua alu atu nai le fofoga o le ua tietie i le solofanua;", "which sword proceeded out of his mouth:"], ["ona maoona ai lea o manu felelei uma i o latou tino.", "and all the fowls were filled with their flesh."]]},
];
renderVerseSet(rev_ch_19_Verses, 'rev-ch19-verses');

var rev_ch_20_Verses = [
  {num:1,words:[["Na a'u iloa foi le agelu ua alu ifo i le lagi, ua ia te ia le ki o le to e le gata,", "And I saw an angel come down from heaven,"], ["ua i lona lima foi le maea uamea tele.", "having the key of the bottomless pit and a great chain in his hand."]]},
  {num:2,words:[["Ua pue foi e ia le tareko,", "And he laid hold on the dragon,"], ["o le gata tuai,", "that old serpent,"], ["o le tiapolo lea ma Satani,", "which is the Devil, and Satan,"], ["ua ia fusifusi foi ia te ia i tausaga e afe.", "and bound him a thousand years,"]]},
  {num:3,words:[["Ua ia lafo foi ia te ia i le to e le gata,", "And cast him into the bottomless pit,"], ["ua pupuni foi ia te ia,", "and shut him up,"], ["ma tuuina atu le faamaufaailoga i ona luga, ina ia le toe faaseseina e ia o nuu,", "and set a seal upon him,"], ["seia atoa ia tausaga e afe;", "that he should deceive the nations no more,"], ["a mavae foi ia,", "till the thousand years should be fulfilled:"], ["e tatau ona tatalaina o ia i nai aso.", "and after that he must be loosed a little season."]]},
  {num:4,words:[["Na a'u iloa foi nofoālii,", "And I saw thrones,"], ["ma ua latou tietie ai,", "and they sat upon them,"], ["ua tuuina atu foi le faamasinoga ia te i latou;", "and judgment was given unto them: and I saw the souls of them that were beheaded for the witness of Jesus,"], ["na a'u iloa foi agaga o e ua vavaeeseina o latou ulu ona o le mau ia Iesu ma le afioga a le Atua,", "and for the word of God,"], ["o e na le ifo i le manu feai po o lona faatagata,", "and which had not worshipped the beast,"], ["na le talia foi le faailoga i o latou muaulu po o latou lima;", "neither his image, neither had received his mark upon their foreheads,"], ["ua latou ola foi,", "or in their hands;"], ["ma ua fai ma tupu faatasi ma Keriso i tausaga e afe;", "and they lived and reigned with Christ a thousand years."]]},
  {num:5,words:[["a o e totoe o e ua oti, e lei toe ola i latou seia atoa ia tausaga e afe.", "But the rest of the dead lived not again until the thousand years were finished."], ["O le uluai toe tu lena.", "This is the first resurrection."]]},
  {num:6,words:[["Amuia mona ua paia le ua i ai se tofi i le uluai toe tu;", "Blessed and holy is he that hath part in the first resurrection:"], ["e le oo foi le pule a le oti faalua ia te i latou,", "on such the second death hath no power,"], ["a e avea i latou ma faitaulaga a le Atua ma Keriso,", "but they shall be priests of God and of Christ,"], ["latou te fai ma tupu foi faatasi ma ia i tausaga e afe.", "and shall reign with him a thousand years."]]},
  {num:7,words:[["Pe a atoa foi ia tausaga e afe,", "And when the thousand years are expired,"], ["ona tatalaina lea o Satani ai le mea na puipuiina ai o ia.", "Satan shall be loosed out of his prison,"]]},
  {num:8,words:[["E alu atu foi o ia e faasese i nuu o i itu e fa o le lalolagi,", "And shall go out to deceive the nations which are in the four quarters of the earth,"], ["o Koku ma Makoku,", "Gog and Magog,"], ["e faapotopoto ia te i latou i le taua,", "to gather them together to battle:"], ["ua pei o le oneone o le sami i latou ona toatele.", "the number of whom is as the sand of the sea."]]},
  {num:9,words:[["Ua o ae foi i latou i le mafolafola o le lalolagi,", "And they went up on the breadth of the earth,"], ["ua latou siomia foi le toagālauapi a le au paia ma le aai ua faapelepeleina;", "and compassed the camp of the saints about,"], ["ona alu ifo lea o le afi mai le Atua i le lagi,", "and the beloved city: and fire came down from God out of heaven,"], ["ua susunu ai ia te i latou;", "and devoured them."]]},
  {num:10,words:[["o le tiapolo foi o le na faasese ia te i latou,", "And the devil that deceived them was cast into the lake of fire and brimstone,"], ["ua lafoina o ia i le lepa afi ma le teio, o i ai le manu feai ma le perofeta pepelo;", "where the beast and the false prophet are,"], ["e puapuagaina ai i latou i le ao ma le po e faavavau faavavau lava.", "and shall be tormented day and night for ever and ever."]]},
  {num:11,words:[["Na a'u iloa foi le nofoālii tele e sinasina,", "And I saw a great white throne,"], ["ma le o tietie ai,", "and him that sat on it,"], ["ua sosola ese le lalolagi ma le lagi i ona luma,", "from whose face the earth and the heaven fled away;"], ["e le iloa foi se mea e tu ai i laua.", "and there was found no place for them."]]},
  {num:12,words:[["Na a'u iloa foi o e na oti,", "And I saw the dead,"], ["o tagatānuu atoa ma alii,", "small and great,"], ["o tutū i luma o le Atua,", "stand before God;"], ["ona fofola lea o tusi;", "and the books were opened:"], ["ua fofola foi ma le tasi tusi,", "and another book was opened,"], ["o le tusi lea o le ola;", "which is the book of life:"], ["ona faamasinoina ai lea o e na oti i mea ua tusia i tusi,", "and the dead were judged out of those things which were written in the books,"], ["e tusa ma a latou amio.", "according to their works."]]},
  {num:13,words:[["Ua avae foi e le sami e na oti sa i ai,", "And the sea gave up the dead which were in it;"], ["ua avae foi e le oti ma seoli e na oti sa i ai;", "and death and hell delivered up the dead which were in them:"], ["e taitasi foi o i latou ma faamasinoina e tusa ma a latou amio.", "and they were judged every man according to their works."]]},
  {num:14,words:[["Ua lafoina foi le oti ma seoli i le lepa afi; o le oti faalua lea.", "And death and hell were cast into the lake of fire. This is the second death."]]},
  {num:15,words:[["Ai se tasi ua iloa ua le tusia i le tusi o le ola, ua lafoina lea i le lepa afi.", "And whosoever was not found written in the book of life was cast into the lake of fire."]]},
];
renderVerseSet(rev_ch_20_Verses, 'rev-ch20-verses');

var rev_ch_21_Verses = [
  {num:1,words:[["Ona a'u iloa lea o le lagi fou ma le lalolagi fou;", "And I saw a new heaven and a new earth:"], ["auā ua mavae atu le uluai lagi, ma le uluai lalolagi,", "for the first heaven and the first earth were passed away;"], ["ua leai foi se toe sami.", "and there was no more sea."]]},
  {num:2,words:[["O a'u foi o Ioane na ou iloa le aai paia,", "And I John saw the holy city,"], ["o Ierusalema fou,", "new Jerusalem,"], ["ua alu ifo mai le Atua i le lagi,", "coming down from God out of heaven,"], ["ua saunia pei o se faatoanofotane ua teuteuina mo lana tane.", "prepared as a bride adorned for her husband."]]},
  {num:3,words:[["Na ou faalogo foi i le leo tele mai le lagi,", "And I heard a great voice out of heaven saying,"], ["ua faapea mai,", "Behold,"], ["Faauta,", "the tabernacle of God is with men,"], ["ua faatasi ma tagata le fale fetafai o le Atua, e mau foi o ia ma i latou;", "and he will dwell with them,"], ["e fai foi i latou mona nuu,", "and they shall be his people,"], ["e ia te i latou le Atua lava,", "and God himself shall be with them,"], ["o lo latou Atua ia.", "and be their God."]]},
  {num:4,words:[["E sōloiesea foi e le Atua loimata uma i o latou mata;", "And God shall wipe away all tears from their eyes;"], ["e leai foi se toe oti,", "and there shall be no more death,"], ["po o se faanoanoa,", "neither sorrow,"], ["po o se aue,", "nor crying,"], ["e leai foi se toe puapuaga;", "neither shall there be any more pain:"], ["auā ua mavae atu mea muamua.", "for the former things are passed away."]]},
  {num:5,words:[["Ua fetalai mai foi lē tietie i le nofoālii,", "And he that sat upon the throne said,"], ["Faauta,", "Behold,"], ["ou te faia ia fou mea uma lava. Ua fetalai mai foi o ia ia te au,", "I make all things new. And he said unto me,"], ["Ia e tusi;", "Write:"], ["auā o upu nei e moni ma le faamaoni ia.", "for these words are true and faithful."]]},
  {num:6,words:[["Ua fetalai mai foi o ia ia te au,", "And he said unto me,"], ["Ua uma ona fai. O a'u le Alefa ma le Omeka,", "It is done. I am Alpha and Omega,"], ["o le amataga ma le gataaga. O le ua fia inu ou te foaifuaina atu ia te ia ai le puna o le vai ola.", "the beginning and the end. I will give unto him that is athirst of the fountain of the water of life freely."]]},
  {num:7,words:[["O lē manumalo e maua e ia mea uma,", "He that overcometh shall inherit all things;"], ["e fai foi a'u mona Atua,", "and I will be his God,"], ["e fai foi o ia mo'u atalii.", "and he shall be my son."]]},
  {num:8,words:[["A o e loto vaivai,", "But the fearful,"], ["ma e lē faalogo,", "and unbelieving,"], ["ma e fai mea e inosia,", "and the abominable,"], ["ma e fasioti tagata,", "and murderers,"], ["ma e faitaaga,", "and whoremongers,"], ["ma e faataulāitu,", "and sorcerers,"], ["ma e ifo i tupua,", "and idolaters,"], ["atoa ma e tala pepelo uma,", "and all liars,"], ["e fai o latou tofi i le lepa e mu i le afi ma le teio,", "shall have their part in the lake which burneth with fire and brimstone:"], ["o le oti faalua lea.", "which is the second death."]]},
  {num:9,words:[["Ua alu ane foi ia te au le tasi o ia agelu e toafitu o e sa i ai ipu e fitu na tutumu i mala e fitu e gata ai,", "And there came unto me one of the seven angels which had the seven vials full of the seven last plagues,"], ["ua tautala mai foi o ia ia te au,", "and talked with me,"], ["ua faapea mai,", "saying,"], ["Sau ia,", "Come hither,"], ["ou te faaali atu ia te oe le faatoanofotane,", "I will shew thee the bride,"], ["o le faletua lea o le Tamai mamoe.", "the Lamb's wife."]]},
  {num:10,words:[["Ua ia avea foi a'u i le Agaga i le mauga tele ma le maualuga,", "And he carried me away in the spirit to a great and high mountain,"], ["ua ia faaali foi ia te au Ierusalema,", "and shewed me that great city,"], ["o le aai tele ma le paia,", "the holy Jerusalem,"], ["o loo alu ifo i le lagi mai le Atua,", "descending out of heaven from God,"]]},
  {num:11,words:[["ua i ai le pupula o le Atua;", "Having the glory of God:"], ["o lona pupula foi e pei o se maa tāua lava,", "and her light was like unto a stone most precious, even like a jasper stone,"], ["e pei o se maa iasepi i lona faatioata mai;", "clear as crystal;"]]},
  {num:12,words:[["ua i ai foi le pa tele ma le maualuga,", "And had a wall great and high,"], ["ua i ai puipui e sefulu ma le lua,", "and had twelve gates,"], ["ua i puipui foi agelu e toasefulu ma le toalua,", "and at the gates twelve angels,"], ["ua tusia ai foi igoa,", "and names written thereon,"], ["o igoa ia o itu aiga e sefulu ma le lua o le fanauga a Isaraelu,", "which are the names of the twelve tribes of the children of Israel:"]]},
  {num:13,words:[["ua i sasaē o puipui e tolu,", "On the east three gates;"], ["ua i le itu i matu o puipui e tolu,", "on the north three gates;"], ["ua i le itu i toga o puipui e tolu,", "on the south three gates;"], ["ua i sisifo o puipui e tolu.", "and on the west three gates."]]},
  {num:14,words:[["Ua i le pa foi o le aai o faavae e sefulu ma le lua,", "And the wall of the city had twelve foundations,"], ["ua i ai foi igoa o le au aposetolo a le Tamai mamoe e toasefulu ma le toalua.", "and in them the names of the twelve apostles of the Lamb."]]},
  {num:15,words:[["O le na tautala ma a'u sa i ai le u auro e fua a'i e ia le aai,", "And he that talked with me had a golden reed to measure the city,"], ["ma ona puipui,", "and the gates thereof,"], ["atoa ma ona pa.", "and the wall thereof."]]},
  {num:16,words:[["Ua faatu faatāfafa foi le aai, o lona umi ua tusa ma lona lautele;", "And the city lieth foursquare,"], ["ua fuatia foi e ia o le aai i le u, e sefulu afe ma afe e lua o setatio;", "and the length is as large as the breadth:"], ["o lona umi, ma le lautele,", "and he measured the city with the reed,"], ["ma le maualuga, ua tutusa lava ia.", "twelve thousand furlongs. The length and the breadth and the height of it are equal."]]},
  {num:17,words:[["Ua fuatia foi e ia lona pa,", "And he measured the wall thereof,"], ["e tasi le selau ma le fagafulu ma le fa o kupita,", "an hundred and forty and four cubits,"], ["o le fua a le tagata,", "according to the measure of a man, that is,"], ["o a le agelu lea.", "of the angel."]]},
  {num:18,words:[["Ua ati foi lona pa i maa iasepi;", "And the building of the wall of it was of jasper:"], ["o le aai o le auro lelei lea,", "and the city was pure gold,"], ["ua pei o le tioata manino.", "like unto clear glass."]]},
  {num:19,words:[["Ua teteu foi noopa o le aai i maa tāua uma;", "And the foundations of the wall of the city were garnished with all manner of precious stones. The first foundation was jasper;"], ["o le noopa muamua o le iasepi lea,", "the second, sapphire;"], ["o lona lua o le safaira lea,", "the third,"], ["o lona tolu o le kakito lea,", "a chalcedony; the fourth,"], ["o lona fa o le samaraki lea;", "an emerald;"]]},
  {num:20,words:[["o lona lima o le saritonu lea,", "The fifth, sardonyx;"], ["o lona ono o le salikea lea,", "the sixth, sardius;"], ["o lona fitu o le tasesa lea,", "the seventh, chrysolite;"], ["o lona valu o le soama lea,", "the eighth, beryl;"], ["o lona iva o le topasi lea,", "the ninth, a topaz;"], ["o lona sefulu o le kuasopera lea,", "the tenth, a chrysoprasus;"], ["o lona sefulu ma le tasi o le uakini lea,", "the eleventh, a jacinth;"], ["o lona sefulu ma le lua o le aselama lea.", "the twelfth, an amethyst."]]},
  {num:21,words:[["O puipui foi e sefulu ma le lua o penina ia e sefulu ma le lua;", "And the twelve gates were twelve pearls;"], ["taitasi le puipui ma le penina e tasi na fai a'i;", "every several gate was of one pearl:"], ["o le ala tele foi o le aai o le auro lelei lea,", "and the street of the city was pure gold,"], ["e pei o le tioata manino.", "as it were transparent glass."]]},
  {num:22,words:[["Ou te lei iloa ai foi se malumalu; auā o lona malumalu o le Alii le Atua lea,", "And I saw no temple therein:"], ["e ona le malosi uma lava, atoa ma le Tamai mamoe.", "for the Lord God Almighty and the Lamb are the temple of it."]]},
  {num:23,words:[["E le aoga foi i le aai ona pupula i ai o le la,", "And the city had no need of the sun,"], ["po o le masina;", "neither of the moon,"], ["auā o le pupula o le Atua ua faamalamalamaina ai ia,", "to shine in it: for the glory of God did lighten it,"], ["o le Tamai mamoe foi o lona lamepa lea.", "and the Lamb is the light thereof."]]},
  {num:24,words:[["O nuu foi o e ua faaolaina latou te savavali i lona malamalama;", "And the nations of them which are saved shall walk in the light of it:"], ["o tupu foi o le lalolagi latou te au mai i ai o latou mamalu ma viiga.", "and the kings of the earth do bring their glory and honour into it."]]},
  {num:25,words:[["O ona puipui foi e le punitia lava i le ao;", "And the gates of it shall not be shut at all by day:"], ["auā e leai se po i lea mea.", "for there shall be no night there."]]},
  {num:26,words:[["Latou te au mai foi i ai le mamalu ma le viiga o nuu.", "And they shall bring the glory and honour of the nations into it."]]},
  {num:27,words:[["E le sao atu lava i ai se mea leaga e tasi,", "And there shall in no wise enter into it any thing that defileth,"], ["po o se na te faia se mea inosia,", "neither whatsoever worketh abomination,"], ["po o se pepelo;", "or maketh a lie:"], ["na o i latou lava e ua tusia i le tusi o le ola a le Tamai mamoe.", "but they which are written in the Lamb's book of life."]]},
];
renderVerseSet(rev_ch_21_Verses, 'rev-ch21-verses');

var rev_ch_22_Verses = [
  {num:1,words:[["Ona faaali mai lea e ia ia te au le vaitafe manino o le vai o le ola,", "And he shewed me a pure river of water of life,"], ["e manino e pei o le maa tioata,", "clear as crystal,"], ["ua tafe ifo mai le nofoālii o le Atua ma le Tamai mamoe.", "proceeding out of the throne of God and of the Lamb."]]},
  {num:2,words:[["O i le moa o lona ala tele ma itu taitasi o le vaitafe le laau o le ola,", "In the midst of the street of it, and on either side of the river,"], ["o loo fua mai i fuata e sefulu ma le lua,", "was there the tree of life,"], ["e taitasi le masina ma fua mai ai lona fuata;", "which bare twelve manner of fruits,"], ["o lau foi o le laau e faamalolo ai nuu.", "and yielded her fruit every month: and the leaves of the tree were for the healing of the nations."]]},
  {num:3,words:[["E leai foi se toe faafano e tasi;", "And there shall be no more curse:"], ["e i ai foi le nofoālii o le Atua ma le Tamai mamoe,", "but the throne of God and of the Lamb shall be in it;"], ["o ana auauna foi latou te auauna ia te ia;", "and his servants shall serve him:"]]},
  {num:4,words:[["latou te vaavaai atu foi i ona fofoga,", "And they shall see his face;"], ["e i ai foi i o latou muaulu lona suafa.", "and his name shall be in their foreheads."]]},
  {num:5,words:[["E leai lava se po i lea mea;", "And there shall be no night there;"], ["e le aoga foi ia te i latou se lamepa,", "and they need no candle,"], ["po o le malamalama o le la;", "neither light of the sun;"], ["auā o le Alii le Atua na te faamalamalamaina i latou;", "for the Lord God giveth them light:"], ["latou te fai ma tupu foi e faavavau faavavau lava.", "and they shall reign for ever and ever."]]},
  {num:6,words:[["Ona fai mai lea o ia ia te au,", "And he said unto me,"], ["O upu e faamaoni ia ma le moni;", "These sayings are faithful and true:"], ["o le Alii foi le Atua o le au perofeta paia ua auina mai e ia lana agelu e faailoa mai i ana auauna mea e tusa ona vave oo mai.", "and the Lord God of the holy prophets sent his angel to shew unto his servants the things which must shortly be done."]]},
  {num:7,words:[["Faauta,", "Behold,"], ["ou te vave alu atu;", "I come quickly:"], ["amuia lē tausi i upu o le valoaga o lenei tusi.", "blessed is he that keepeth the sayings of the prophecy of this book."]]},
  {num:8,words:[["O a'u foi o Ioane,", "And I John saw these things,"], ["na ou vaai ma ou faalogo i na mea; ua ou faalogo ma ou vaai,", "and heard them. And when I had heard and seen,"], ["ona a'u faapaū lea e ifo atu i vae o le agelu na na faaali mai ia te au ia mea.", "I fell down to worship before the feet of the angel which shewed me these things."]]},
  {num:9,words:[["A ua fai mai o ia ia te au,", "Then saith he unto me,"], ["Ia oe,", "See thou do it not:"], ["aua lava; auā o a'u o lou uso a auauna,", "for I am thy fellowservant,"], ["ma lo le au perofeta ou uso,", "and of thy brethren the prophets,"], ["o lo latou foi o e tausi i upu o lenei tusi;", "and of them which keep the sayings of this book:"], ["ia e ifo i le Atua.", "worship God."]]},
  {num:10,words:[["Ua fai mai foi o ia ia te au,", "And he saith unto me,"], ["Aua e te faamaufaailogaina upu o le valoaga o lenei tusi;", "Seal not the sayings of the prophecy of this book:"], ["auā ua latalata ona aso.", "for the time is at hand."]]},
  {num:11,words:[["O lē amioletonu ia amioletonu pea o ia,", "He that is unjust, let him be unjust still:"], ["o lē eleelea ia eleelea pea o ia,", "and he which is filthy, let him be filthy still:"], ["o lē amiotonu ia amiotonu pea o ia,", "and he that is righteous, let him be righteous still:"], ["o lē paia ia paia pea o ia.", "and he that is holy, let him be holy still."]]},
  {num:12,words:[["Faauta foi,", "And, behold,"], ["ou te vave alu atu;", "I come quickly;"], ["ua ia te au foi le taui ou te taui taitasi atu ia tusa ma lana ua fai.", "and my reward is with me, to give every man according as his work shall be."]]},
  {num:13,words:[["O a'u le Alefa ma le Omeka,", "I am Alpha and Omega,"], ["o le amataga ma le gataaga,", "the beginning and the end,"], ["o le muamua ma le mulimuli.", "the first and the last."]]},
  {num:14,words:[["Amuia i latou o e faia ana poloaiga,", "Blessed are they that do his commandments,"], ["ina ia taga ia i latou le laau o le ola,", "that they may have right to the tree of life,"], ["ma ia latou ulu atu i le aai i ona faitotoa.", "and may enter in through the gates into the city."]]},
  {num:15,words:[["A ua i tuapā o ulī,", "For without are dogs,"], ["ma e faataulāitu,", "and sorcerers,"], ["ma e faitaaga,", "and whoremongers,"], ["ma e fasioti tagata,", "and murderers,"], ["ma e ifo i tupua,", "and idolaters,"], ["atoa uma lava e ua loto i le tala pepelo ma latou faia.", "and whosoever loveth and maketh a lie."]]},
  {num:16,words:[["O a'u o Iesu na ou auina atu la'u agelu e molimau ia te outou i ia mea i ekalesia. O a'u o le Aa ma le fanau a Tavita,", "I Jesus have sent mine angel to testify unto you these things in the churches. I am the root and the offspring of David,"], ["o le fetu ao pupula.", "and the bright and morning star."]]},
  {num:17,words:[["Ua fetalai mai le Agaga ma le faatoanofotane, Ina sau ia;", "And the Spirit and the bride say,"], ["ina fai atu foi ia o lē faalogo, Ina sau ia;", "Come. And let him that heareth say,"], ["o lē fia inu, ina sau ia,", "Come. And let him that is athirst come. And whosoever will,"], ["atoa ma lē manao i ai, ina ave fua ia le vai o le ola.", "let him take the water of life freely."]]},
  {num:18,words:[["Auā ou te ta'utino atu ia i latou uma o e faalogo i upu o le valoaga o lenei tusi,", "For I testify unto every man that heareth the words of the prophecy of this book,"], ["Ai se tasi e faaopoopo mai se upu i nei upu,", "If any man shall add unto these things,"], ["e faaopoopoina atu e le Atua ia te ia o mala ua tusia i lenei tusi.", "God shall add unto him the plagues that are written in this book:"]]},
  {num:19,words:[["Ai se tasi foi e ave ese se upu i upu o le tusi o lenei valoaga,", "And if any man shall take away from the words of the book of this prophecy,"], ["e aveeseina e le Atua lona tofi i le tusi o le ola,", "God shall take away his part out of the book of life,"], ["ma le aai paia,", "and out of the holy city,"], ["ma mea ua tusia i lenei tusi.", "and from the things which are written in this book."]]},
  {num:20,words:[["Ua fai mai lē molimau i nei mea, E moni,", "He which testifieth these things saith,"], ["ou te vave alu atu.", "Surely I come quickly."], ["Amene.", "Amen."], ["O lea lava,", "Even so,"], ["le Alii e Iesu,", "come,"], ["ia e afio mai.", "Lord Jesus."]]},
  {num:21,words:[["Ia ia te outou uma le alofa tunoa o lo tatou Alii o Iesu Keriso. Amene.", "The grace of our Lord Jesus Christ be with you all. Amen."]]},
];
renderVerseSet(rev_ch_22_Verses, 'rev-ch22-verses');

})();